  1→#!/usr/bin/env bun
  2→/**
  3→ * Context window sweep: translates with 100%, 50%, 25% of full transcript/SRT context.
  4→ *
  5→ * Reuses existing per-chunk transcriptions (from with_srt runs).
  6→ * Converts relative timestamps to absolute, then slices by time window.
  7→ * Calls Gemini 2.5 Pro directly for translation, then parses into SRT.
  8→ *
  9→ * Usage:
 10→ *   bun run context-sweep
 11→ *   bun run context-sweep -- --level 100   # only run 100%
 12→ */
 13→
 14→import { existsSync, readFileSync, writeFileSync, mkdirSync } from "fs";
 15→import { join } from "path";
 16→import { Command } from "commander";
 17→import { GoogleGenAI } from "@google/genai";
 18→import { parseTranslationResponse } from "../src/parser/response_parser.js";
 19→
 20→// ── Config ─────────────────────────────────────────────────────────────────
 21→
 22→const VIDEO_NAME =
 23→  "AnimePahe_Tamayura_-_Sotsugyou_Shashin_Part_3_-_Akogare_-_01_BD_720p_Nishi-Taku";
 24→const DATA_DIR = join(import.meta.dir, "..", "data");
 25→const EXISTING_OUTPUT = join(DATA_DIR, "output", `${VIDEO_NAME}_chunked`);
 26→const REF_SRT_PATH = join(DATA_DIR, "tamayura-sotsugyou-shashin-part3-akogare-ep1-english.srt");
 27→const SWEEP_OUTPUT = join(DATA_DIR, "output", "context_sweep");
 28→const PROMPT_TEMPLATE = readFileSync(
 29→  join(import.meta.dir, "..", "src", "translator", "translation_prompt.template"),
 30→  "utf-8"
 31→);
 32→
 33→const GEMINI_MODEL = "gemini-2.5-pro";
 34→const TARGET_LANGUAGE = "Korean";
 35→const TARGET_TAG = "korean";
 36→const SOURCE_LANGUAGE = "Japanese";
 37→
 38→// Chunk boundaries from our chunking script (absolute seconds)
 39→const CHUNK_OFFSETS = [0, 314.8, 627.0, 936.6, 1250.5, 1562.0, 1871.4, 2186.3, 2497.9, 2806.2, 3116.7];
 40→
 41→// ── SRT helpers ────────────────────────────────────────────────────────────
 42→
 43→interface SrtEntry {
 44→  index: number;
 45→  start: number;
 46→  end: number;
 47→  text: string;
 48→  raw: string;
 49→}
 50→
 51→function tsToSecs(ts: string): number {
 52→  const [h, m, rest] = ts.split(":");
 53→  const [s, ms] = rest.split(",");
 54→  return parseInt(h) * 3600 + parseInt(m) * 60 + parseInt(s) + parseInt(ms) / 1000;
 55→}
 56→
 57→function secsToTs(secs: number): string {
 58→  if (secs < 0) secs = 0;
 59→  const h = Math.floor(secs / 3600);
 60→  const m = Math.floor((secs % 3600) / 60);
 61→  const s = Math.floor(secs % 60);
 62→  const ms = Math.round((secs % 1) * 1000);
 63→  return `${String(h).padStart(2, "0")}:${String(m).padStart(2, "0")}:${String(s).padStart(2, "0")},${String(ms).padStart(3, "0")}`;
 64→}
 65→
 66→function parseSrtFull(path: string): SrtEntry[] {
 67→  let text = readFileSync(path, "utf-8");
 68→  if (text.charCodeAt(0) === 0xfeff) text = text.slice(1);
 69→  const blocks = text.trim().split(/\n\n+/);
 70→  const entries: SrtEntry[] = [];
 71→  for (const block of blocks) {
 72→    const lines = block.trim().split("\n");
 73→    if (lines.length < 2) continue;
 74→    const index = parseInt(lines[0].trim());
 75→    if (isNaN(index)) continue;
 76→    const m = lines[1].match(/(\d{2}:\d{2}:\d{2},\d{3})\s*-->\s*(\d{2}:\d{2}:\d{2},\d{3})/);
 77→    if (!m) continue;
 78→    entries.push({
 79→      index,
 80→      start: tsToSecs(m[1]),
 81→      end: tsToSecs(m[2]),
 82→      text: lines.slice(2).join("\n"),
 83→      raw: block.trim(),
 84→    });
 85→  }
 86→  return entries;
 87→}
 88→
 89→function srtEntriesToString(entries: SrtEntry[]): string {
 90→  return entries.map((e) => e.raw).join("\n\n") + "\n";
 91→}
 92→
 93→// ── Load and absolutize transcripts ────────────────────────────────────────
 94→
 95→interface TranscriptLine {
 96→  absoluteStart: number;
 97→  absoluteEnd: number;
 98→  text: string;
 99→  rawLine: string; // line with absolute timestamps
100→}
101→
102→function loadAllTranscriptLines(): TranscriptLine[] {
103→  const allLines: TranscriptLine[] = [];
104→  const mmssTimingRegex = /(\d{1,2}:\d{2})\s*-\s*(\d{1,2}:\d{2})/;
105→  const hhmmssTimingRegex = /(\d{2}:\d{2}:\d{2},\d{3})\s*-->\s*(\d{2}:\d{2}:\d{2},\d{3})/;
106→
107→  for (let i = 0; i < 10; i++) {
108→    const chunkId = `chunk${String(i + 1).padStart(2, "0")}`;
109→    const offset = CHUNK_OFFSETS[i];
110→    const path = join(
111→      EXISTING_OUTPUT, chunkId, "with_srt", "intermediates", "transcripts", "part01_adjusted.txt"
112→    );
113→    if (!existsSync(path)) {
114→      console.error(`Missing transcript: ${path}`);
115→      continue;
116→    }
117→
118→    const content = readFileSync(path, "utf-8");
119→    for (const line of content.split("\n")) {
120→      if (!line.trim()) continue;
121→
122→      // Try HH:MM:SS,mmm --> HH:MM:SS,mmm format (adjusted transcripts)
123→      let match = line.match(hhmmssTimingRegex);
124→      if (match) {
125→        const relStart = tsToSecs(match[1]);
126→        const relEnd = tsToSecs(match[2]);
127→        const absStart = relStart + offset;
128→        const absEnd = relEnd + offset;
129→        const textPart = line.replace(match[0], "").replace(/^[\s\-\)]+/, "").trim();
130→        const absLine = `${secsToTs(absStart)} --> ${secsToTs(absEnd)} - ${textPart}`;
131→        allLines.push({ absoluteStart: absStart, absoluteEnd: absEnd, text: textPart, rawLine: absLine });
132→        continue;
133→      }
134→
135→      // Try mm:ss - mm:ss format (raw transcripts)
136→      match = line.match(mmssTimingRegex);
137→      if (match) {
138→        const parseMmSs = (s: string) => {
139→          const [m, sec] = s.split(":").map(Number);
140→          return m * 60 + sec;
141→        };
142→        const relStart = parseMmSs(match[1]);
143→        const relEnd = parseMmSs(match[2]);
144→        const absStart = relStart + offset;
145→        const absEnd = relEnd + offset;
146→        const textPart = line.replace(match[0], "").replace(/^[\s\-\)]+/, "").replace(/^relative\s*\(/, "").trim();
147→        const absLine = `${secsToTs(absStart)} --> ${secsToTs(absEnd)} - ${textPart}`;
148→        allLines.push({ absoluteStart: absStart, absoluteEnd: absEnd, text: textPart, rawLine: absLine });
149→        continue;
150→      }
151→
152→      // Non-timestamped line, include as-is
153→      if (line.trim().length > 0) {
154→        allLines.push({ absoluteStart: -1, absoluteEnd: -1, text: line.trim(), rawLine: line.trim() });
155→      }
156→    }
157→  }
158→
159→  // Sort by absolute time
160→  allLines.sort((a, b) => a.absoluteStart - b.absoluteStart);
161→  return allLines;
162→}
163→
164→// ── Build context windows ──────────────────────────────────────────────────
165→
166→interface ContextWindow {
167→  label: string;
168→  transcript: string;
169→  srtContent: string;
170→  srtEntries: SrtEntry[];
171→  startTime: number;
172→  endTime: number;
173→}
174→
175→function buildWindows(
176→  level: number,
177→  allTranscriptLines: TranscriptLine[],
178→  allSrt: SrtEntry[]
179→): ContextWindow[] {
180→  const totalStart = 0;
181→  const totalEnd = CHUNK_OFFSETS[CHUNK_OFFSETS.length - 1];
182→  const totalDuration = totalEnd - totalStart;
183→
184→  const fullTranscript = allTranscriptLines.map((l) => l.rawLine).join("\n");
185→
186→  if (level === 100) {
187→    return [
188→      {
189→        label: "100pct_full",
190→        transcript: fullTranscript,
191→        srtContent: srtEntriesToString(allSrt),
192→        srtEntries: allSrt,
193→        startTime: totalStart,
194→        endTime: totalEnd,
195→      },
196→    ];
197→  }
198→
199→  const numWindows = Math.round(100 / level);
200→  const windowDuration = totalDuration / numWindows;
201→  const windows: ContextWindow[] = [];
202→
203→  for (let w = 0; w < numWindows; w++) {
204→    const wStart = totalStart + w * windowDuration;
205→    const wEnd = totalStart + (w + 1) * windowDuration;
206→
207→    // Filter transcript lines by absolute time
208→    const windowLines = allTranscriptLines.filter(
209→      (l) => l.absoluteStart >= 0 && l.absoluteStart >= wStart && l.absoluteStart < wEnd
210→    );
211→    const windowSrt = allSrt.filter(
212→      (e) => e.start >= wStart && e.start < wEnd
213→    );
214→
215→    windows.push({
216→      label: `${level}pct_part${w + 1}of${numWindows}`,
217→      transcript: windowLines.map((l) => l.rawLine).join("\n"),
218→      srtContent: srtEntriesToString(windowSrt),
219→      srtEntries: windowSrt,
220→      startTime: wStart,
221→      endTime: wEnd,
222→    });
223→  }
224→
225→  return windows;
226→}
227→
228→// ── Call Gemini ─────────────────────────────────────────────────────────────
229→
230→async function callGeminiTranslation(
231→  prompt: string,
232→  label: string
233→): Promise<string> {
234→  const apiKey = process.env.GEMINI_API_KEY;
235→  if (!apiKey) throw new Error("GEMINI_API_KEY not set");
236→
237→  const ai = new GoogleGenAI({ apiKey });
238→  console.log(`  [${label}] Calling Gemini 2.5 Pro...`);
239→  const startTime = Date.now();
240→
241→  let fullResponse = "";
242→  const response = await ai.models.generateContentStream({
243→    model: GEMINI_MODEL,
244→    config: { responseMimeType: "text/plain" },
245→    contents: [{ role: "user", parts: [{ text: prompt }] }],
246→  });
247→
248→  for await (const chunk of response) {
249→    fullResponse += chunk.text;
250→  }
251→
252→  const elapsed = ((Date.now() - startTime) / 1000).toFixed(1);
253→  console.log(
254→    `  [${label}] Done in ${elapsed}s (${fullResponse.length} chars)`
255→  );
256→  return fullResponse;
257→}
258→
259→// ── Build prompt ───────────────────────────────────────────────────────────
260→
261→function buildPrompt(transcript: string, srtContent: string): string {
262→  let prompt = PROMPT_TEMPLATE;
263→  prompt = prompt.replace("{ADJUSTED_TRANSCRIPT}", transcript);
264→  prompt = prompt.replace("{REFERENCE_SRT}", srtContent);
265→  prompt = prompt.replace(/{SOURCE_LANGUAGE_NAME}/g, SOURCE_LANGUAGE);
266→  prompt = prompt.replace(/{TARGET_LANGUAGE_NAME}/g, TARGET_LANGUAGE);
267→  prompt = prompt.replace(/{TARGET_LANGUAGE_TAG}/g, TARGET_TAG);
268→  const xmlExample = `<${TARGET_TAG}_translation>[Your translation for ${TARGET_LANGUAGE}]</${TARGET_TAG}_translation>`;
269→  prompt = prompt.replace("{TARGET_LANGUAGE_XML_EXAMPLE}", xmlExample);
270→  return prompt;
271→}
272→
273→// ── Parse response to SRT ──────────────────────────────────────────────────
274→
275→function responseToSrt(responseText: string, label: string): string {
276→  const { entries, issues } = parseTranslationResponse(responseText, 1, [
277→    TARGET_LANGUAGE,
278→  ]);
279→
280→  const errors = issues.filter((i) => i.severity === "error").length;
281→  const warnings = issues.filter((i) => i.severity === "warning").length;
282→  console.log(
283→    `  [${label}] Parsed ${entries.length} entries (${errors} errors, ${warnings} warnings)`
284→  );
285→
286→  let srt = "";
287→  entries.forEach((entry, idx) => {
288→    const timing = entry.originalTiming || "00:00:00,000 --> 00:00:00,000";
289→    const english = entry.translations["english"] || entry.originalLine || "";
290→    const target = entry.translations[TARGET_LANGUAGE] || "";
291→
292→    srt += `${idx + 1}\n`;
293→    srt += `${timing}\n`;
294→    srt += `<font color="#FFFFFF">${english}</font>\n`;
295→    srt += `<font color="#FFC0CB">${target}</font>\n\n`;
296→  });
297→
298→  return srt;
299→}
300→
301→// ── Main ───────────────────────────────────────────────────────────────────
302→
303→const program = new Command();
304→program
305→  .name("context-sweep")
306→  .description("Translate with varying context window sizes (100%, 50%, 25%)")
307→  .option("-l, --level <levels>", "Comma-separated levels to run (default: 100,50,25)", "100,50,25")
308→  .parse();
309→
310→const opts = program.opts();
311→const levels = opts.level.split(",").map(Number);
312→
313→console.log("=".repeat(70));
314→console.log("  Context Window Sweep");
315→console.log("=".repeat(70));
316→
317→// Load data
318→const allTranscriptLines = loadAllTranscriptLines();
319→console.log(`Loaded ${allTranscriptLines.length} transcript lines (absolute timestamps)`);
320→console.log(`  Time range: ${secsToTs(allTranscriptLines[0]?.absoluteStart ?? 0)} - ${secsToTs(allTranscriptLines[allTranscriptLines.length - 1]?.absoluteEnd ?? 0)}`);
321→
322→const allSrt = parseSrtFull(REF_SRT_PATH);
323→console.log(`Loaded ${allSrt.length} reference SRT entries`);
324→
325→mkdirSync(SWEEP_OUTPUT, { recursive: true });
326→
327→// Build all windows across all levels
328→interface Job {
329→  level: number;
330→  window: ContextWindow;
331→  prompt: string;
332→}
333→
334→const jobs: Job[] = [];
335→for (const level of levels) {
336→  const windows = buildWindows(level, allTranscriptLines, allSrt);
337→  console.log(`\nLevel ${level}%: ${windows.length} window(s)`);
338→  for (const w of windows) {
339→    const prompt = buildPrompt(w.transcript, w.srtContent);
340→    console.log(
341→      `  ${w.label}: ${w.srtEntries.length} ref subs, ${w.transcript.split("\n").length} transcript lines, prompt ${prompt.length} chars`
342→    );
343→    jobs.push({ level, window: w, prompt });
344→  }
345→}
346→
347→// Run all jobs in parallel
348→console.log(`\nLaunching ${jobs.length} translation calls in parallel...`);
349→
350→const results = await Promise.allSettled(
351→  jobs.map(async (job) => {
352→    const outDir = join(SWEEP_OUTPUT, `${job.level}pct`);
353→    mkdirSync(outDir, { recursive: true });
354→
355→    const responseText = await callGeminiTranslation(
356→      job.prompt,
357→      job.window.label
358→    );
359→
360→    // Save raw response
361→    writeFileSync(
362→      join(outDir, `${job.window.label}_response.txt`),
363→      responseText
364→    );
365→
366→    // Parse to SRT
367→    const srt = responseToSrt(responseText, job.window.label);
368→    const srtPath = join(outDir, `${job.window.label}.bilingual.srt`);
369→    writeFileSync(srtPath, srt);
370→
371→    console.log(`  [${job.window.label}] Saved: ${srtPath}`);
372→    return { label: job.window.label, srtPath, entryCount: srt.split(/\n\n+/).filter(b => b.trim()).length };
373→  })
374→);
375→
376→// Summary
377→console.log("\n" + "=".repeat(70));
378→console.log("  Results");
379→console.log("=".repeat(70));
380→for (const r of results) {
381→  if (r.status === "fulfilled") {
382→    console.log(`  OK: ${r.value.label} (${r.value.entryCount} entries) -> ${r.value.srtPath}`);
383→  } else {
384→    console.log(`  FAIL: ${r.reason}`);
385→  }
386→}
387→
388→console.log(`\nOutput at: ${SWEEP_OUTPUT}/`);
389→

  1→#!/usr/bin/env bun
  2→/**
  3→ * Generates per-chunk sample comparison files for agent-based ranking.
  4→ * Outputs: data/output/context_sweep/rankings/chunkNN_samples.txt
  5→ */
  6→
  7→import { readFileSync, writeFileSync, mkdirSync, existsSync } from "fs";
  8→import { join } from "path";
  9→
 10→const DATA_DIR = join(import.meta.dir, "..", "..", "data");
 11→const VIDEO_NAME = "AnimePahe_Tamayura_-_Sotsugyou_Shashin_Part_3_-_Akogare_-_01_BD_720p_Nishi-Taku";
 12→const CHUNKED_BASE = join(DATA_DIR, "output", `${VIDEO_NAME}_chunked`);
 13→const SWEEP_BASE = join(DATA_DIR, "output", "context_sweep");
 14→const REF_SRT = join(DATA_DIR, "tamayura-sotsugyou-shashin-part3-akogare-ep1-english.srt");
 15→const OUT_DIR = join(DATA_DIR, "output", "context_sweep", "rankings");
 16→
 17→const CHUNK_OFFSETS = [0, 314.8, 627.0, 936.6, 1250.5, 1562.0, 1871.4, 2186.3, 2497.9, 2806.2, 3116.7];
 18→const P25_BOUNDS = [0, 779.175, 1558.35, 2337.525, 3116.7];
 19→const P25_FILES = ["25pct_part1of4.bilingual.srt", "25pct_part2of4.bilingual.srt", "25pct_part3of4.bilingual.srt", "25pct_part4of4.bilingual.srt"];
 20→const P50_BOUNDS = [0, 1558.35, 3116.7];
 21→const P50_FILES = ["50pct_part1of2.bilingual.srt", "50pct_part2of2.bilingual.srt"];
 22→
 23→interface Sub { index: number; start: number; end: number; text: string; }
 24→
 25→function tsToSecs(ts: string): number {
 26→  const [h, m, rest] = ts.split(":");
 27→  const [s, ms] = rest.split(",");
 28→  return parseInt(h) * 3600 + parseInt(m) * 60 + parseInt(s) + parseInt(ms) / 1000;
 29→}
 30→
 31→function parseSrt(path: string, englishOnly: boolean): Sub[] {
 32→  if (!existsSync(path)) return [];
 33→  let text = readFileSync(path, "utf-8");
 34→  if (text.charCodeAt(0) === 0xfeff) text = text.slice(1);
 35→  const blocks = text.trim().split(/\n\n+/);
 36→  const entries: Sub[] = [];
 37→  for (const block of blocks) {
 38→    const lines = block.trim().split("\n");
 39→    if (lines.length < 2) continue;
 40→    const idx = parseInt(lines[0].trim());
 41→    if (isNaN(idx)) continue;
 42→    const m = lines[1].match(/(\d{2}:\d{2}:\d{2},\d{3})\s*-->\s*(\d{2}:\d{2}:\d{2},\d{3})/);
 43→    if (!m) continue;
 44→    const textLines = lines.slice(2);
 45→    let body: string;
 46→    if (englishOnly) {
 47→      body = textLines.map(l => l.replace(/<\/?font[^>]*>/gi, "").replace(/<\/?i>/gi, "").trim()).filter(l => l.length > 0)[0] || "";
 48→    } else {
 49→      body = textLines.map(l => l.replace(/<\/?[^>]+>/g, "").trim()).filter(l => l.length > 0).join(" ");
 50→    }
 51→    entries.push({ index: idx, start: tsToSecs(m[1]), end: tsToSecs(m[2]), text: body });
 52→  }
 53→  return entries;
 54→}
 55→
 56→function findNearest(subs: Sub[], t: number): Sub | null {
 57→  let best: Sub | null = null, bestD = Infinity;
 58→  for (const s of subs) { const d = Math.abs(s.start - t); if (d < bestD) { bestD = d; best = s; } }
 59→  return best && bestD <= 10 ? best : null;
 60→}
 61→
 62→function get25File(t: number): string {
 63→  for (let i = 0; i < 4; i++) if (t >= P25_BOUNDS[i] && t < P25_BOUNDS[i + 1]) return join(SWEEP_BASE, "25pct", P25_FILES[i]);
 64→  return join(SWEEP_BASE, "25pct", P25_FILES[3]);
 65→}
 66→function get50File(t: number): string {
 67→  return t < P50_BOUNDS[1] ? join(SWEEP_BASE, "50pct", P50_FILES[0]) : join(SWEEP_BASE, "50pct", P50_FILES[1]);
 68→}
 69→
 70→mkdirSync(OUT_DIR, { recursive: true });
 71→
 72→const allRef = parseSrt(REF_SRT, false);
 73→const subs100 = parseSrt(join(SWEEP_BASE, "100pct", "100pct_full.bilingual.srt"), true);
 74→const fileCache = new Map<string, Sub[]>();
 75→function getCached(p: string): Sub[] { if (!fileCache.has(p)) fileCache.set(p, parseSrt(p, true)); return fileCache.get(p)!; }
 76→
 77→for (let c = 0; c < 10; c++) {
 78→  const chunkNum = c + 1;
 79→  const chunkId = `chunk${String(chunkNum).padStart(2, "0")}`;
 80→  const cStart = CHUNK_OFFSETS[c], cEnd = CHUNK_OFFSETS[c + 1];
 81→
 82→  const chunkRef = allRef.filter(s => s.start >= cStart && s.start < cEnd);
 83→  const raw10 = parseSrt(join(CHUNKED_BASE, chunkId, "no_srt", "video.bilingual.korean.srt"), true);
 84→  const subs10 = raw10.map(s => ({ ...s, start: s.start + cStart, end: s.end + cStart }));
 85→
 86→  // Random 10
 87→  const picked = [...chunkRef].sort(() => Math.random() - 0.5).slice(0, 10);
 88→  picked.sort((a, b) => a.start - b.start);
 89→
 90→  let out = `CHUNK ${chunkNum} — Translation Ranking Task\n`;
 91→  out += `For each line, pick which translation (A/B/C/D) best matches the REFERENCE in meaning, tone, and naturalness.\n`;
 92→  out += `If a translation says "(no match)" or "[SKIP THIS SUBTITLE]", it cannot win.\n\n`;
 93→
 94→  picked.forEach((ref, i) => {
 95→    const ts = `${Math.floor(ref.start / 60)}:${String(Math.floor(ref.start % 60)).padStart(2, "0")}`;
 96→    const s25 = getCached(get25File(ref.start));
 97→    const s50 = getCached(get50File(ref.start));
 98→    const m10 = findNearest(subs10, ref.start);
 99→    const m25 = findNearest(s25, ref.start);
100→    const m50 = findNearest(s50, ref.start);
101→    const m100 = findNearest(subs100, ref.start);
102→
103→    out += `--- Line ${i + 1} (${ts}) ---\n`;
104→    out += `REFERENCE: "${ref.text}"\n`;
105→    out += `A (10%):  "${m10?.text || "(no match)"}"\n`;
106→    out += `B (25%):  "${m25?.text || "(no match)"}"\n`;
107→    out += `C (50%):  "${m50?.text || "(no match)"}"\n`;
108→    out += `D (100%): "${m100?.text || "(no match)"}"\n\n`;
109→  });
110→
111→  const outPath = join(OUT_DIR, `${chunkId}_samples.txt`);
112→  writeFileSync(outPath, out);
113→  console.log(`${chunkId}: ${picked.length} samples -> ${outPath}`);
114→}
115→
116→console.log(`\nDone. Output in ${OUT_DIR}/`);
117→

  1→#!/usr/bin/env bun
  2→/**
  3→ * Compare multiple SRT files line-by-line against a reference.
  4→ * Shows each subtitle's text across all sources side by side.
  5→ *
  6→ * Usage:
  7→ *   bun scripts/compare_context/compare.ts \
  8→ *     --ref data/tamayura-...-english.srt \
  9→ *     --srt "10%=data/output/.../no_srt/video.bilingual.korean.srt" \
 10→ *     --srt "25%=data/output/context_sweep/25pct/25pct_part1of4.bilingual.srt" \
 11→ *     --srt "50%=data/output/context_sweep/50pct/50pct_part1of2.bilingual.srt"
 12→ *
 13→ *   Labels are optional: --srt path.srt  (uses filename as label)
 14→ */
 15→
 16→import { readFileSync } from "fs";
 17→import { basename } from "path";
 18→import { Command } from "commander";
 19→
 20→// ── SRT parsing ────────────────────────────────────────────────────────────
 21→
 22→interface Sub {
 23→  index: number;
 24→  start: number;
 25→  end: number;
 26→  text: string;
 27→}
 28→
 29→function tsToSecs(ts: string): number {
 30→  const [h, m, rest] = ts.split(":");
 31→  const [s, ms] = rest.split(",");
 32→  return parseInt(h) * 3600 + parseInt(m) * 60 + parseInt(s) + parseInt(ms) / 1000;
 33→}
 34→
 35→function shortTs(secs: number): string {
 36→  const m = Math.floor(secs / 60);
 37→  const s = Math.floor(secs % 60);
 38→  return `${m}:${String(s).padStart(2, "0")}`;
 39→}
 40→
 41→function parseSrt(path: string, englishOnly: boolean): Sub[] {
 42→  let text = readFileSync(path, "utf-8");
 43→  if (text.charCodeAt(0) === 0xfeff) text = text.slice(1);
 44→  const blocks = text.trim().split(/\n\n+/);
 45→  const entries: Sub[] = [];
 46→  for (const block of blocks) {
 47→    const lines = block.trim().split("\n");
 48→    if (lines.length < 2) continue;
 49→    const index = parseInt(lines[0].trim());
 50→    if (isNaN(index)) continue;
 51→    const m = lines[1].match(/(\d{2}:\d{2}:\d{2},\d{3})\s*-->\s*(\d{2}:\d{2}:\d{2},\d{3})/);
 52→    if (!m) continue;
 53→    const textLines = lines.slice(2);
 54→    let body: string;
 55→    if (englishOnly) {
 56→      body = textLines
 57→        .map((l) => l.replace(/<\/?font[^>]*>/gi, "").replace(/<\/?i>/gi, "").trim())
 58→        .filter((l) => l.length > 0)[0] || "";
 59→    } else {
 60→      body = textLines
 61→        .map((l) => l.replace(/<\/?[^>]+>/g, "").trim())
 62→        .filter((l) => l.length > 0)
 63→        .join(" ");
 64→    }
 65→    entries.push({ index, start: tsToSecs(m[1]), end: tsToSecs(m[2]), text: body });
 66→  }
 67→  return entries;
 68→}
 69→
 70→// ── Matching ───────────────────────────────────────────────────────────────
 71→
 72→function matchToRef(refSubs: Sub[], genSubs: Sub[]): Map<number, Sub> {
 73→  // Map ref index -> nearest gen sub (many ref can match same gen)
 74→  const map = new Map<number, Sub>();
 75→  for (const ref of refSubs) {
 76→    let best: Sub | null = null;
 77→    let bestDist = Infinity;
 78→    for (const gen of genSubs) {
 79→      const dist = Math.abs(gen.start - ref.start);
 80→      if (dist < bestDist) {
 81→        bestDist = dist;
 82→        best = gen;
 83→      }
 84→    }
 85→    if (best && bestDist <= 10) {
 86→      map.set(ref.index, best);
 87→    }
 88→  }
 89→  return map;
 90→}
 91→
 92→// ── Display ────────────────────────────────────────────────────────────────
 93→
 94→function truncate(s: string, len: number): string {
 95→  return s.length > len ? s.slice(0, len - 1) + "…" : s;
 96→}
 97→
 98→// ── Main ───────────────────────────────────────────────────────────────────
 99→
100→const program = new Command();
101→program
102→  .name("compare")
103→  .description("Compare multiple SRT translations against a reference")
104→  .requiredOption("-r, --ref <path>", "Reference SRT file")
105→  .option("-s, --srt <label=path...>", "SRT files to compare (repeatable)", (val: string, prev: string[]) => [...prev, val], [])
106→  .option("--from <seconds>", "Start time filter (seconds)")
107→  .option("--to <seconds>", "End time filter (seconds)")
108→  .parse();
109→
110→const opts = program.opts();
111→
112→// Parse labeled SRT inputs
113→interface Source {
114→  label: string;
115→  subs: Sub[];
116→  matched: Map<number, Sub>;
117→}
118→
119→const refSubs = parseSrt(opts.ref, false);
120→const sources: Source[] = [];
121→
122→for (const arg of opts.srt) {
123→  let label: string;
124→  let path: string;
125→  if (arg.includes("=")) {
126→    [label, path] = arg.split("=", 2);
127→  } else {
128→    path = arg;
129→    label = basename(path, ".srt").replace(".bilingual", "");
130→  }
131→  const subs = parseSrt(path, true);
132→  const matched = matchToRef(refSubs, subs);
133→  sources.push({ label, subs, matched });
134→}
135→
136→// Filter by time range
137→const fromTime = opts.from ? parseFloat(opts.from) : 0;
138→const toTime = opts.to ? parseFloat(opts.to) : Infinity;
139→const filteredRef = refSubs.filter((s) => s.start >= fromTime && s.start <= toTime);
140→
141→// Column widths
142→const COL = 50;
143→const labels = sources.map((s) => s.label);
144→const headerLabels = ["REF", ...labels];
145→
146→// Print header
147→console.log();
148→console.log("  " + "Time".padEnd(8) + headerLabels.map((l) => l.padEnd(COL)).join("│ "));
149→console.log("  " + "─".repeat(8) + headerLabels.map(() => "─".repeat(COL)).join("┼─"));
150→
151→for (const ref of filteredRef) {
152→  const time = shortTs(ref.start);
153→  const refText = truncate(ref.text, COL - 1);
154→
155→  const cols = sources.map((src) => {
156→    const gen = src.matched.get(ref.index);
157→    if (!gen) return "(no match)".padEnd(COL);
158→    return truncate(gen.text, COL - 1).padEnd(COL);
159→  });
160→
161→  console.log("  " + time.padEnd(8) + refText.padEnd(COL) + "│ " + cols.join("│ "));
162→}
163→
164→// Summary
165→console.log("  " + "─".repeat(8) + headerLabels.map(() => "─".repeat(COL)).join("┼─"));
166→console.log();
167→console.log(`  Reference: ${filteredRef.length} subs`);
168→for (const src of sources) {
169→  const matched = filteredRef.filter((r) => src.matched.has(r.index)).length;
170→  console.log(`  ${src.label}: ${src.subs.length} total subs, ${matched}/${filteredRef.length} matched`);
171→}
