  1→#!/usr/bin/env bun
  2→/**
  3→ * For each chunk, pick 10 random reference subs, show all context levels'
  4→ * translations, and use Claude to rank which best matches the reference.
  5→ * Outputs per-chunk JSON verdicts, then tallies the final result.
  6→ *
  7→ * Usage:
  8→ *   bun scripts/compare_context/rank_samples.ts
  9→ */
 10→
 11→import { readFileSync, writeFileSync, mkdirSync, existsSync } from "fs";
 12→import { join } from "path";
 13→import Anthropic from "@anthropic-ai/sdk";
 14→
 15→// ── Config ─────────────────────────────────────────────────────────────────
 16→
 17→const DATA_DIR = join(import.meta.dir, "..", "..", "data");
 18→const VIDEO_NAME = "AnimePahe_Tamayura_-_Sotsugyou_Shashin_Part_3_-_Akogare_-_01_BD_720p_Nishi-Taku";
 19→const CHUNKED_BASE = join(DATA_DIR, "output", `${VIDEO_NAME}_chunked`);
 20→const SWEEP_BASE = join(DATA_DIR, "output", "context_sweep");
 21→const REF_SRT = join(DATA_DIR, "tamayura-sotsugyou-shashin-part3-akogare-ep1-english.srt");
 22→const OUT_DIR = join(DATA_DIR, "output", "context_sweep", "rankings");
 23→
 24→const CHUNK_OFFSETS = [0, 314.8, 627.0, 936.6, 1250.5, 1562.0, 1871.4, 2186.3, 2497.9, 2806.2, 3116.7];
 25→const SAMPLES_PER_CHUNK = 10;
 26→
 27→// 25% window boundaries: 4 windows
 28→const P25_BOUNDS = [0, 779.175, 1558.35, 2337.525, 3116.7];
 29→const P25_FILES = [
 30→  "25pct_part1of4.bilingual.srt", "25pct_part2of4.bilingual.srt",
 31→  "25pct_part3of4.bilingual.srt", "25pct_part4of4.bilingual.srt"
 32→];
 33→// 50% window boundaries: 2 windows
 34→const P50_BOUNDS = [0, 1558.35, 3116.7];
 35→const P50_FILES = ["50pct_part1of2.bilingual.srt", "50pct_part2of2.bilingual.srt"];
 36→
 37→// ── SRT parsing ────────────────────────────────────────────────────────────
 38→
 39→interface Sub { index: number; start: number; end: number; text: string; }
 40→
 41→function tsToSecs(ts: string): number {
 42→  const [h, m, rest] = ts.split(":");
 43→  const [s, ms] = rest.split(",");
 44→  return parseInt(h) * 3600 + parseInt(m) * 60 + parseInt(s) + parseInt(ms) / 1000;
 45→}
 46→
 47→function parseSrt(path: string, englishOnly: boolean): Sub[] {
 48→  if (!existsSync(path)) return [];
 49→  let text = readFileSync(path, "utf-8");
 50→  if (text.charCodeAt(0) === 0xfeff) text = text.slice(1);
 51→  const blocks = text.trim().split(/\n\n+/);
 52→  const entries: Sub[] = [];
 53→  for (const block of blocks) {
 54→    const lines = block.trim().split("\n");
 55→    if (lines.length < 2) continue;
 56→    const index = parseInt(lines[0].trim());
 57→    if (isNaN(index)) continue;
 58→    const m = lines[1].match(/(\d{2}:\d{2}:\d{2},\d{3})\s*-->\s*(\d{2}:\d{2}:\d{2},\d{3})/);
 59→    if (!m) continue;
 60→    const textLines = lines.slice(2);
 61→    let body: string;
 62→    if (englishOnly) {
 63→      body = textLines.map(l => l.replace(/<\/?font[^>]*>/gi, "").replace(/<\/?i>/gi, "").trim())
 64→        .filter(l => l.length > 0)[0] || "";
 65→    } else {
 66→      body = textLines.map(l => l.replace(/<\/?[^>]+>/g, "").trim()).filter(l => l.length > 0).join(" ");
 67→    }
 68→    entries.push({ index, start: tsToSecs(m[1]), end: tsToSecs(m[2]), text: body });
 69→  }
 70→  return entries;
 71→}
 72→
 73→function findNearest(subs: Sub[], targetStart: number): Sub | null {
 74→  let best: Sub | null = null;
 75→  let bestDist = Infinity;
 76→  for (const s of subs) {
 77→    const d = Math.abs(s.start - targetStart);
 78→    if (d < bestDist) { bestDist = d; best = s; }
 79→  }
 80→  return best && bestDist <= 10 ? best : null;
 81→}
 82→
 83→// ── Pick which 25%/50% file covers a given time ───────────────────────────
 84→
 85→function get25File(absTime: number): string {
 86→  for (let i = 0; i < 4; i++) {
 87→    if (absTime >= P25_BOUNDS[i] && absTime < P25_BOUNDS[i + 1])
 88→      return join(SWEEP_BASE, "25pct", P25_FILES[i]);
 89→  }
 90→  return join(SWEEP_BASE, "25pct", P25_FILES[3]);
 91→}
 92→
 93→function get50File(absTime: number): string {
 94→  return absTime < P50_BOUNDS[1]
 95→    ? join(SWEEP_BASE, "50pct", P50_FILES[0])
 96→    : join(SWEEP_BASE, "50pct", P50_FILES[1]);
 97→}
 98→
 99→// ── Random sampling ────────────────────────────────────────────────────────
100→
101→function sampleN<T>(arr: T[], n: number): T[] {
102→  const shuffled = [...arr].sort(() => Math.random() - 0.5);
103→  return shuffled.slice(0, n);
104→}
105→
106→// ── Build samples for a chunk ──────────────────────────────────────────────
107→
108→interface Sample {
109→  refText: string;
110→  refStart: number;
111→  translations: Record<string, string>; // "10%" -> text, "25%" -> text, etc.
112→}
113→
114→function buildChunkSamples(chunkIdx: number): Sample[] {
115→  const chunkId = `chunk${String(chunkIdx + 1).padStart(2, "0")}`;
116→  const chunkStart = CHUNK_OFFSETS[chunkIdx];
117→  const chunkEnd = CHUNK_OFFSETS[chunkIdx + 1];
118→
119→  // Reference subs in this chunk's time range
120→  const allRef = parseSrt(REF_SRT, false);
121→  const chunkRef = allRef.filter(s => s.start >= chunkStart && s.start < chunkEnd);
122→  if (chunkRef.length === 0) return [];
123→
124→  // 10% subs (relative timestamps — add chunk offset for matching)
125→  const raw10 = parseSrt(join(CHUNKED_BASE, chunkId, "no_srt", "video.bilingual.korean.srt"), true);
126→  const subs10 = raw10.map(s => ({ ...s, start: s.start + chunkStart, end: s.end + chunkStart }));
127→
128→  // 25%, 50%, 100% (absolute timestamps)
129→  // Cache parsed files to avoid re-parsing
130→  const fileCache = new Map<string, Sub[]>();
131→  function getSubs(path: string): Sub[] {
132→    if (!fileCache.has(path)) fileCache.set(path, parseSrt(path, true));
133→    return fileCache.get(path)!;
134→  }
135→
136→  const subs100 = getSubs(join(SWEEP_BASE, "100pct", "100pct_full.bilingual.srt"));
137→
138→  const picked = sampleN(chunkRef, Math.min(SAMPLES_PER_CHUNK, chunkRef.length));
139→
140→  return picked.map(ref => {
141→    const subs25 = getSubs(get25File(ref.start));
142→    const subs50 = getSubs(get50File(ref.start));
143→
144→    const m10 = findNearest(subs10, ref.start);
145→    const m25 = findNearest(subs25, ref.start);
146→    const m50 = findNearest(subs50, ref.start);
147→    const m100 = findNearest(subs100, ref.start);
148→
149→    return {
150→      refText: ref.text,
151→      refStart: ref.start,
152→      translations: {
153→        "10%": m10?.text || "(no match)",
154→        "25%": m25?.text || "(no match)",
155→        "50%": m50?.text || "(no match)",
156→        "100%": m100?.text || "(no match)",
157→      },
158→    };
159→  });
160→}
161→
162→// ── Claude ranking ─────────────────────────────────────────────────────────
163→
164→interface Ranking {
165→  refText: string;
166→  refStart: number;
167→  winner: string;
168→  reason: string;
169→}
170→
171→async function rankWithClaude(samples: Sample[], chunkNum: number): Promise<Ranking[]> {
172→  const apiKey = process.env.ANTHROPIC_API_KEY;
173→  if (!apiKey) throw new Error("ANTHROPIC_API_KEY not set");
174→
175→  const client = new Anthropic({ apiKey });
176→
177→  const lines = samples.map((s, i) => {
178→    const ts = `${Math.floor(s.refStart / 60)}:${String(Math.floor(s.refStart % 60)).padStart(2, "0")}`;
179→    return `### Line ${i + 1} (${ts})
180→**Reference:** "${s.refText}"
181→- **A (10%):** "${s.translations["10%"]}"
182→- **B (25%):** "${s.translations["25%"]}"
183→- **C (50%):** "${s.translations["50%"]}"
184→- **D (100%):** "${s.translations["100%"]}"`;
185→  }).join("\n\n");
186→
187→  const prompt = `You are comparing subtitle translations against a human reference translation.
188→For each line, pick which translation (A=10%, B=25%, C=50%, D=100%) best matches the reference in meaning, tone, and naturalness. If a translation says "(no match)" or "[SKIP THIS SUBTITLE]", it cannot win.
189→
190→Respond with ONLY a JSON array, no other text:
191→[{"line": 1, "winner": "B", "reason": "closest wording"}, ...]
192→
193→${lines}`;
194→
195→  console.log(`  Chunk ${chunkNum}: calling Claude...`);
196→  const response = await client.messages.create({
197→    model: "claude-sonnet-4-20250514",
198→    max_tokens: 2000,
199→    messages: [{ role: "user", content: prompt }],
200→  });
201→
202→  const text = response.content[0].type === "text" ? response.content[0].text : "";
203→  // Extract JSON from response
204→  const jsonMatch = text.match(/\[[\s\S]*\]/);
205→  if (!jsonMatch) throw new Error(`Failed to parse Claude response for chunk ${chunkNum}: ${text}`);
206→
207→  const parsed: { line: number; winner: string; reason: string }[] = JSON.parse(jsonMatch[0]);
208→
209→  const levelMap: Record<string, string> = { A: "10%", B: "25%", C: "50%", D: "100%" };
210→
211→  return parsed.map(p => ({
212→    refText: samples[p.line - 1].refText,
213→    refStart: samples[p.line - 1].refStart,
214→    winner: levelMap[p.winner] || p.winner,
215→    reason: p.reason,
216→  }));
217→}
218→
219→// ── Main ───────────────────────────────────────────────────────────────────
220→
221→mkdirSync(OUT_DIR, { recursive: true });
222→
223→console.log("=".repeat(60));
224→console.log("  Context Sweep: Automated Ranking (10 lines x 10 chunks)");
225→console.log("=".repeat(60));
226→
227→const allRankings: Ranking[] = [];
228→
229→for (let c = 0; c < 10; c++) {
230→  const chunkNum = c + 1;
231→  const samples = buildChunkSamples(c);
232→  if (samples.length === 0) {
233→    console.log(`  Chunk ${chunkNum}: no samples, skipping`);
234→    continue;
235→  }
236→
237→  const rankings = await rankWithClaude(samples, chunkNum);
238→
239→  // Save per-chunk JSON
240→  const outPath = join(OUT_DIR, `chunk${String(chunkNum).padStart(2, "0")}_rankings.json`);
241→  writeFileSync(outPath, JSON.stringify(rankings, null, 2));
242→  console.log(`  Chunk ${chunkNum}: saved ${rankings.length} rankings -> ${outPath}`);
243→
244→  allRankings.push(...rankings);
245→}
246→
247→// ── Tally ──────────────────────────────────────────────────────────────────
248→
249→console.log("\n" + "=".repeat(60));
250→console.log("  FINAL TALLY");
251→console.log("=".repeat(60));
252→
253→const tally: Record<string, number> = { "10%": 0, "25%": 0, "50%": 0, "100%": 0 };
254→for (const r of allRankings) {
255→  if (tally[r.winner] !== undefined) tally[r.winner]++;
256→}
257→
258→const total = allRankings.length;
259→for (const [level, count] of Object.entries(tally).sort((a, b) => b[1] - a[1])) {
260→  const pct = ((count / total) * 100).toFixed(1);
261→  const bar = "█".repeat(Math.round(count / total * 40));
262→  console.log(`  ${level.padEnd(5)} ${String(count).padStart(3)} / ${total}  (${pct}%)  ${bar}`);
263→}
264→
265→// Save combined results
266→const tallyPath = join(OUT_DIR, "final_tally.json");
267→writeFileSync(tallyPath, JSON.stringify({ tally, total, rankings: allRankings }, null, 2));
268→console.log(`\nFull results: ${tallyPath}`);
