  6→const DEFAULT_TEMPLATE_PATH = __dirname + "/translation_prompt.template";
  7→
  8→/**
  9→ * Loads the prompt template content.
 10→ * @param templatePath Optional path to the template file.
 11→ * @returns The template string or null if not found/readable.
 12→ */
 13→async function loadPromptTemplate(
 14→  templatePath?: string
 15→): Promise<string | null> {
 16→  const path = templatePath || DEFAULT_TEMPLATE_PATH;
 17→  if (!existsSync(path)) {
 18→    logger.error(`Prompt template file not found: ${path}`);
 19→    return null;
 20→  }
 21→  try {
 22→    const template = await readFile(path, "utf-8");
 23→    logger.debug(`Loaded prompt template from: ${path}`);
 24→    return template;
 25→  } catch (error: any) {
 26→    logger.error(
 27→      `Failed to read prompt template ${path}: ${error.message || error}`
 28→    );
 29→    return null;
 30→  }
 31→}
 32→
 33→/**
 34→ * Generates the prompt for the translation LLM.
 35→ * Assumes config.targetLanguages contains exactly one language.
 36→ */
 37→export async function generateTranslationPrompt(
 38→  chunk: ChunkInfo,
 39→  config: Config
 40→): Promise<string | null> {
 41→  const template = await loadPromptTemplate(
 42→    config.translationPromptTemplatePath
 43→  );
 44→  if (!template) {
 45→    return null;
 46→  }
 47→
 48→  if (!config.targetLanguages || config.targetLanguages.length === 0) {
 49→    logger.error(
 50→      "No target languages specified in config for translation prompt."
 51→    );
 52→    return null;
 53→  }
 54→  // Use only the first target language
 55→  const targetLanguage = config.targetLanguages[0];
 56→  if (config.targetLanguages.length > 1) {
 57→    logger.warn(
 58→      `Multiple target languages provided, but only using the first one for translation: ${targetLanguage}`
 59→    );
 60→  }
 61→
 62→  // Read adjusted transcript
 63→  if (
 64→    !chunk.adjustedTranscriptPath ||
 65→    !existsSync(chunk.adjustedTranscriptPath)
 66→  ) {
 67→    logger.error(
 68→      `[Chunk ${chunk.partNumber}] Adjusted transcript missing: ${chunk.adjustedTranscriptPath}`
 69→    );
 70→    return null;
 71→  }
 72→  let adjustedTranscriptContent = "";
 73→  try {
 74→    adjustedTranscriptContent = await readFile(
 75→      chunk.adjustedTranscriptPath,
 76→      "utf-8"
 77→    );
 78→  } catch (error: any) {
 79→    logger.error(
 80→      `[Chunk ${chunk.partNumber}] Failed to read adjusted transcript ${
 81→        chunk.adjustedTranscriptPath
 82→      }: ${error.message || error}`
 83→    );
 84→    return null;
 85→  }
 86→
 87→  // Read reference SRT (optional)
 88→  let referenceSrtContent = "";
 89→  if (chunk.srtChunkPath && existsSync(chunk.srtChunkPath)) {
 90→    try {
 91→      referenceSrtContent = await readFile(chunk.srtChunkPath, "utf-8");
 92→    } catch (error: any) {
 93→      logger.warn(
 94→        `[Chunk ${chunk.partNumber}] Failed to read reference SRT ${chunk.srtChunkPath}. Proceeding without it.`
 95→      );
 96→    }
 97→  } else {
 98→    logger.warn(
 99→      `[Chunk ${chunk.partNumber}] Reference SRT missing: ${chunk.srtChunkPath}. Proceeding without it.`
100→    );
101→  }
102→
103→  // --- Populate Template ---
104→  let populatedPrompt = template;
105→
106→  // Get source language (if provided)
107→  const sourceLanguage = config.sourceLanguages?.[0] || "the source language";
108→  if (config.sourceLanguages && config.sourceLanguages.length > 1) {
109→    logger.warn(
110→      `[Chunk ${chunk.partNumber}] Multiple source languages provided: ${config.sourceLanguages.join(", ")}. Using first one: ${config.sourceLanguages[0]}`
111→    );
112→  }
113→
114→  populatedPrompt = populatedPrompt.replace(
115→    "{ADJUSTED_TRANSCRIPT}",
116→    adjustedTranscriptContent
117→  );
118→  populatedPrompt = populatedPrompt.replace(
119→    "{REFERENCE_SRT}",
120→    referenceSrtContent || "[Reference SRT not available]"
121→  );
122→
123→  // Replace source language placeholders
124→  populatedPrompt = populatedPrompt.replace(
125→    /{SOURCE_LANGUAGE_NAME}/g,
126→    sourceLanguage
127→  );
128→
129→  // Replace target language placeholders
130→  populatedPrompt = populatedPrompt.replace(
131→    /{TARGET_LANGUAGE_NAME}/g,
132→    targetLanguage
133→  );
134→
135→  // Create and replace the target language tag placeholder
136→  const targetLangTag = targetLanguage.toLowerCase().replace(/\s+/g, "_");
137→  populatedPrompt = populatedPrompt.replace(
138→    /{TARGET_LANGUAGE_TAG}/g,
139→    targetLangTag
140→  );
141→
142→  // Legacy support: Replace old XML example placeholder if it exists
143→  const xmlExample = `<${targetLangTag}_translation>[Your translation for ${targetLanguage}]</${targetLangTag}_translation>`;
144→  populatedPrompt = populatedPrompt.replace(
145→    "{TARGET_LANGUAGE_XML_EXAMPLE}",
146→    xmlExample
147→  );
148→
149→  logger.debug(
150→    `[Chunk ${chunk.partNumber}] Generated translation prompt for English + ${targetLanguage} (source: ${sourceLanguage}).`
151→  );
152→  return populatedPrompt;
153→}
