  1→import chalk from "chalk";
  2→import {
  3→  type ParsedTranslationEntry,
  4→  type ProcessingIssue,
  5→  type ParsingIssueType,
  6→} from "../types.js";
  7→import * as logger from "../utils/logger.js";
  8→
  9→// --- Constants ---
 10→const CONTEXT_SNIPPET_LENGTH = 150;
 11→const MM_SS_REGEX = /^(\d{1,2}):(\d{2})$/;
 12→const HH_MM_SS_REGEX = /^(\d{1,2}):(\d{2}):(\d{2})$/;
 13→
 14→// --- Result Interface for Internal Use ---
 15→interface InternalParseResult {
 16→  entries: ParsedTranslationEntry[];
 17→  issues: ProcessingIssue[];
 18→  summary: {
 19→    // Keep summary for potential internal logging or reporting
 20→    totalEntriesAttempted: number;
 21→    successfullyParsed: number;
 22→    markdownBlocksProcessed: number;
 23→    directTagsProcessed: number;
 24→    errors: number;
 25→    warnings: number;
 26→  };
 27→}
 28→
 29→// --- Utility Functions (Adapted) ---
 30→
 31→/** Calculates approximate line number based on character index */
 32→function getLineNumber(content: string, index: number): number {
 33→  const validIndex = Math.max(0, Math.min(index, content.length));
 34→  return content.substring(0, validIndex).split("\n").length;
 35→}
 36→
 37→/** Adds a parsing issue to the provided list. */
 38→function addIssue(
 39→  issuesList: ProcessingIssue[],
 40→  issueDetails: Omit<ProcessingIssue, "lineNumber" | "context" | "type"> & {
 41→    type: ParsingIssueType;
 42→    contextSnippet?: string;
 43→  },
 44→  charIndex?: number,
 45→  fullContent?: string
 46→) {
 47→  const context = issueDetails.contextSnippet
 48→    ? issueDetails.contextSnippet.substring(0, CONTEXT_SNIPPET_LENGTH) +
 49→      (issueDetails.contextSnippet.length > CONTEXT_SNIPPET_LENGTH ? "..." : "")
 50→    : charIndex !== undefined && fullContent
 51→    ? fullContent.substring(charIndex, charIndex + CONTEXT_SNIPPET_LENGTH) +
 52→      (fullContent.length > charIndex + CONTEXT_SNIPPET_LENGTH ? "..." : "")
 53→    : undefined;
 54→
 55→  const fullIssue: ProcessingIssue = {
 56→    ...issueDetails,
 57→    lineNumber:
 58→      charIndex !== undefined && fullContent
 59→        ? getLineNumber(fullContent, charIndex)
 60→        : undefined,
 61→    context: context,
 62→  };
 63→  issuesList.push(fullIssue);
 64→  // No console logging here, handled by caller if needed
 65→}
 66→
 67→// --- Timing Parsers (Adapted from original) ---
 68→function timeToSeconds(time: string): number {
 69→  const timeStr = time.replace(",", ".");
 70→  const parts = timeStr.split(":");
 71→  if (parts.length !== 3) throw new Error(`Invalid time format: "${time}"`);
 72→  const hours = parseInt(parts[0], 10);
 73→  const minutes = parseInt(parts[1], 10);
 74→  const secondsWithMs = parseFloat(parts[2]);
 75→  if (
 76→    isNaN(hours) ||
 77→    isNaN(minutes) ||
 78→    isNaN(secondsWithMs) ||
 79→    hours < 0 ||
 80→    minutes < 0 ||
 81→    minutes > 59 ||
 82→    secondsWithMs < 0 ||
 83→    secondsWithMs >= 60
 84→  ) {
 85→    throw new Error(`Invalid time components in "${time}"`);
 86→  }
 87→  return hours * 3600 + minutes * 60 + secondsWithMs;
 88→}
 89→
 90→function parseMmSs(time: string): number {
 91→  const match = time.match(MM_SS_REGEX);
 92→  if (!match) throw new Error(`Invalid time format: "${time}"`);
 93→  const minutes = parseInt(match[1], 10);
 94→  const seconds = parseInt(match[2], 10);
 95→  if (
 96→    isNaN(minutes) ||
 97→    isNaN(seconds) ||
 98→    minutes < 0 ||
 99→    seconds < 0 ||
100→    seconds > 59
101→  ) {
102→    throw new Error(`Invalid time components in "${time}"`);
103→  }
104→  return minutes * 60 + seconds;
105→}
106→
107→function parseHhMmSs(time: string): number {
108→  const match = time.match(HH_MM_SS_REGEX);
109→  if (!match) throw new Error(`Invalid time format: "${time}"`);
110→  const hours = parseInt(match[1], 10);
111→  const minutes = parseInt(match[2], 10);
112→  const seconds = parseInt(match[3], 10);
113→  if (
114→    isNaN(hours) ||
115→    isNaN(minutes) ||
116→    isNaN(seconds) ||
117→    hours < 0 ||
118→    minutes < 0 ||
119→    minutes > 59 ||
120→    seconds < 0 ||
121→    seconds > 59
122→  ) {
123→    throw new Error(`Invalid time components in "${time}"`);
124→  }
125→  return hours * 3600 + minutes * 60 + seconds;
126→}
127→
128→function isValidTiming(start?: number, end?: number): boolean {
129→  return (
130→    start !== undefined &&
131→    end !== undefined &&
132→    !isNaN(start) &&
133→    !isNaN(end) &&
134→    end > start
135→  );
136→}
137→
138→// --- Tag Extraction (Adapted) ---
139→function extractNestedTagContent(
140→  content: string,
141→  tagNames: string | string[],
142→  issuesList: ProcessingIssue[],
143→  contextInfo: {
144→    fullContent: string;
145→    searchStartIndex: number;
146→    currentId?: string;
147→  }
148→): string | null {
149→  if (!Array.isArray(tagNames)) tagNames = [tagNames];
150→
151→  for (const tagName of tagNames) {
152→    const escapedTagName = tagName.replace(/[.*+?^${}()|[\\]\\]/g, "\\$&");
153→    const startTagRegex = new RegExp(`<${escapedTagName}(\\s+[^>]*)?>`, "i");
154→    const startMatch = content.match(startTagRegex);
155→
156→    if (startMatch && startMatch.index !== undefined) {
157→      const openTag = startMatch[0];
158→      const openTagIndex = startMatch.index;
159→      const valueStartIndex = openTagIndex + openTag.length;
160→      const closeTagMarkerIndex = content.indexOf("</", valueStartIndex);
161→
162→      if (closeTagMarkerIndex !== -1) {
163→        const extractedContent = content
164→          .substring(valueStartIndex, closeTagMarkerIndex)
165→          .trim();
166→        const closingTagMatch = content
167→          .substring(closeTagMarkerIndex)
168→          .match(/<\/([^>]+)>/);
169→        if (closingTagMatch) {
170→          const actualClosingTagName = closingTagMatch[1].trim();
171→          const expectedClosingTag = `</${tagName}>`;
172→          if (actualClosingTagName.toLowerCase() !== tagName.toLowerCase()) {
173→            addIssue(
174→              issuesList,
175→              {
176→                type: "MalformedTag",
177→                severity: "warning",
178→                subtitleId: contextInfo.currentId,
179→                message: `Found opening tag '<${tagName}>' but next closing tag was '</${actualClosingTagName}>' (expected '${expectedClosingTag}'). Using content anyway.`,
180→                contextSnippet: content.substring(
181→                  openTagIndex,
182→                  Math.min(
183→                    content.length,
184→                    closeTagMarkerIndex + closingTagMatch[0].length + 10
185→                  )
186→                ),
187→              },
188→              contextInfo.searchStartIndex + openTagIndex,
189→              contextInfo.fullContent
190→            );
191→          }
192→        }
193→        return extractedContent;
194→      } else {
195→        addIssue(
196→          issuesList,
197→          {
198→            type: "MalformedTag",
199→            severity: "warning",
200→            subtitleId: contextInfo.currentId,
201→            message: `Found opening tag '<${tagName}>' but no subsequent closing tag marker '</' was found within the parsed block.`,
202→            contextSnippet: content.substring(openTagIndex),
203→          },
204→          contextInfo.searchStartIndex + openTagIndex,
205→          contextInfo.fullContent
206→        );
207→        return null;
208→      }
209→    }
210→  }
211→  return null;
212→}
213→
214→// --- Core Parsing Logic (Adapted) ---
215→
216→/**
217→ * Extracts subtitle data from a single <subline> block content.
218→ * Adapts output to ParsedTranslationEntry format.
219→ */
220→function extractSublineData(
221→  tagContent: string,
222→  sourceFormat: ParsedTranslationEntry["sourceFormat"],
223→  issuesList: ProcessingIssue[],
224→  contextInfo: {
225→    fullContent: string;
226→    tagStartIndex: number;
227→    sourceChunk: number;
228→    targetLanguages: string[];
229→  }
230→): Omit<ParsedTranslationEntry, "sourceFormat" | "sourceChunk"> | null {
231→  const initialContext = {
232→    ...contextInfo,
233→    searchStartIndex: contextInfo.tagStartIndex,
234→  };
235→  const number = extractNestedTagContent(
236→    tagContent,
237→    ["original_number", "number", "id"],
238→    issuesList,
239→    initialContext
240→  );
241→
242→  if (!number) {
243→    if (!/<\/?(?:original_number|number|id)/i.test(tagContent)) {
244→      addIssue(
245→        issuesList,
246→        {
247→          type: "NumberNotFound",
248→          severity: "error",
249→          message: "Missing <original_number> tag.",
250→          contextSnippet: tagContent,
251→        },
252→        contextInfo.tagStartIndex,
253→        contextInfo.fullContent
254→      );
255→    } else {
256→      addIssue(
257→        issuesList,
258→        {
259→          type: "ExtractionFailed",
260→          severity: "error",
261→          message:
262→            "Found potential <original_number> tag but failed to extract content.",
263→          contextSnippet: tagContent,
264→        },
265→        contextInfo.tagStartIndex,
266→        contextInfo.fullContent
267→      );
268→    }
269→    return null;
270→  }
271→
272→  const updatedContext = {
273→    ...contextInfo,
274→    currentId: number,
275→    searchStartIndex: contextInfo.tagStartIndex,
276→  };
277→
278→  const originalLine = extractNestedTagContent(
279→    tagContent,
280→    "original_line",
281→    issuesList,
282→    updatedContext
283→  );
284→  const timingValue = extractNestedTagContent(
285→    tagContent,
286→    ["original_timing", "timing"],
287→    issuesList,
288→    updatedContext
289→  );
290→
291→  const translations: Record<string, string | null> = {};
292→  let hasAnyTranslation = false;
293→  translations["english"] = extractNestedTagContent(
294→    tagContent,
295→    ["better_english_translation", "english_translation", "english"],
296→    issuesList,
297→    updatedContext
298→  );
299→  if (translations["english"] !== null) hasAnyTranslation = true;
300→  for (const lang of contextInfo.targetLanguages) {
301→    const safeLangTag = lang.toLowerCase().replace(/\s+/g, "_");
302→    translations[lang] = extractNestedTagContent(
303→      tagContent,
304→      `${safeLangTag}_translation`,
305→      issuesList,
306→      updatedContext
307→    );
308→    if (translations[lang] !== null) hasAnyTranslation = true;
309→  }
310→  if (!hasAnyTranslation) {
311→    addIssue(
312→      issuesList,
313→      {
314→        type: "TextNotFound",
315→        severity: "warning",
316→        subtitleId: number,
317→        message:
318→          "Found ID but failed to extract any English or target language translations.",
319→        contextSnippet: tagContent,
320→      },
321→      contextInfo.tagStartIndex,
322→      contextInfo.fullContent
323→    );
324→  }
325→
326→  let parsedStartTime: number | undefined = undefined;
327→  let parsedEndTime: number | undefined = undefined;
328→  if (timingValue) {
329→    try {
330→      const parts = timingValue.split(" --> ");
331→      if (parts.length === 2) {
332→        parsedStartTime = timeToSeconds(parts[0].trim());
333→        parsedEndTime = timeToSeconds(parts[1].trim());
334→        if (!isValidTiming(parsedStartTime, parsedEndTime)) {
335→          addIssue(
336→            issuesList,
337→            {
338→              type: "InvalidTimingValue",
339→              severity: "warning",
340→              subtitleId: number,
341→              message: `Invalid timing values: ${timingValue}`,
342→              contextSnippet: timingValue,
343→            },
344→            contextInfo.tagStartIndex,
345→            contextInfo.fullContent
346→          );
347→          parsedStartTime = undefined;
348→          parsedEndTime = undefined;
349→        }
350→      } else {
351→        addIssue(
352→          issuesList,
353→          {
354→            type: "InvalidTimingFormat",
355→            severity: "warning",
356→            subtitleId: number,
357→            message: `Invalid timing format (expected -->): ${timingValue}`,
358→            contextSnippet: timingValue,
359→          },
360→          contextInfo.tagStartIndex,
361→          contextInfo.fullContent
362→        );
363→      }
364→    } catch (e: any) {
365→      addIssue(
366→        issuesList,
367→        {
368→          type: "InvalidTimingFormat",
369→          severity: "warning",
370→          subtitleId: number,
371→          message: `Failed to parse timing string components: ${timingValue} - ${e.message}`,
372→          contextSnippet: timingValue,
373→        },
374→        contextInfo.tagStartIndex,
375→        contextInfo.fullContent
376→      );
377→    }
378→  }
