#!/usr/bin/env bun
/**
 * Context window sweep: translates with 100%, 50%, 25% of full transcript/SRT context.
 *
 * Reuses existing per-chunk transcriptions (from with_srt runs).
 * Converts relative timestamps to absolute, then slices by time window.
 * Calls Gemini 2.5 Pro directly for translation, then parses into SRT.
 *
 * Usage:
 *   bun run context-sweep
 *   bun run context-sweep -- --level 100   # only run 100%
 */

import { existsSync, readFileSync, writeFileSync, mkdirSync } from "fs";
import { join } from "path";
import { Command } from "commander";
import { GoogleGenAI } from "@google/genai";
import { parseTranslationResponse } from "../src/parser/response_parser.js";

// ── Config ─────────────────────────────────────────────────────────────────

const VIDEO_NAME =
  "AnimePahe_Tamayura_-_Sotsugyou_Shashin_Part_3_-_Akogare_-_01_BD_720p_Nishi-Taku";
const DATA_DIR = join(import.meta.dir, "..", "data");
const EXISTING_OUTPUT = join(DATA_DIR, "output", `${VIDEO_NAME}_chunked`);
const REF_SRT_PATH = join(DATA_DIR, "tamayura-sotsugyou-shashin-part3-akogare-ep1-english.srt");
const SWEEP_OUTPUT = join(DATA_DIR, "output", "context_sweep");
const SWEEP_OUTPUT_NOSRT = join(DATA_DIR, "output", "context_sweep_nosrt");
const PROMPT_TEMPLATE = readFileSync(
  join(import.meta.dir, "..", "src", "translator", "translation_prompt.template"),
  "utf-8"
);
const PROMPT_TEMPLATE_NOSRT = readFileSync(
  join(import.meta.dir, "..", "src", "translator", "translation_prompt_nosrt.template"),
  "utf-8"
);

const GEMINI_MODEL = "gemini-2.5-pro";
const TARGET_LANGUAGE = "Korean";
const TARGET_TAG = "korean";
const SOURCE_LANGUAGE = "Japanese";

// Chunk boundaries from our chunking script (absolute seconds)
const CHUNK_OFFSETS = [0, 314.8, 627.0, 936.6, 1250.5, 1562.0, 1871.4, 2186.3, 2497.9, 2806.2, 3116.7];

// ── SRT helpers ────────────────────────────────────────────────────────────

interface SrtEntry {
  index: number;
  start: number;
  end: number;
  text: string;
  raw: string;
}

function tsToSecs(ts: string): number {
  const [h, m, rest] = ts.split(":");
  const [s, ms] = rest.split(",");
  return parseInt(h) * 3600 + parseInt(m) * 60 + parseInt(s) + parseInt(ms) / 1000;
}

function secsToTs(secs: number): string {
  if (secs < 0) secs = 0;
  const h = Math.floor(secs / 3600);
  const m = Math.floor((secs % 3600) / 60);
  const s = Math.floor(secs % 60);
  const ms = Math.round((secs % 1) * 1000);
  return `${String(h).padStart(2, "0")}:${String(m).padStart(2, "0")}:${String(s).padStart(2, "0")},${String(ms).padStart(3, "0")}`;
}

function parseSrtFull(path: string): SrtEntry[] {
  let text = readFileSync(path, "utf-8");
  if (text.charCodeAt(0) === 0xfeff) text = text.slice(1);
  const blocks = text.trim().split(/\n\n+/);
  const entries: SrtEntry[] = [];
  for (const block of blocks) {
    const lines = block.trim().split("\n");
    if (lines.length < 2) continue;
    const index = parseInt(lines[0].trim());
    if (isNaN(index)) continue;
    const m = lines[1].match(/(\d{2}:\d{2}:\d{2},\d{3})\s*-->\s*(\d{2}:\d{2}:\d{2},\d{3})/);
    if (!m) continue;
    entries.push({
      index,
      start: tsToSecs(m[1]),
      end: tsToSecs(m[2]),
      text: lines.slice(2).join("\n"),
      raw: block.trim(),
    });
  }
  return entries;
}

function srtEntriesToString(entries: SrtEntry[]): string {
  return entries.map((e) => e.raw).join("\n\n") + "\n";
}

// ── Load and absolutize transcripts ────────────────────────────────────────

interface TranscriptLine {
  absoluteStart: number;
  absoluteEnd: number;
  text: string;
  rawLine: string; // line with absolute timestamps
}

function loadAllTranscriptLines(): TranscriptLine[] {
  const allLines: TranscriptLine[] = [];
  const mmssTimingRegex = /(\d{1,2}:\d{2})\s*-\s*(\d{1,2}:\d{2})/;
  const hhmmssTimingRegex = /(\d{2}:\d{2}:\d{2},\d{3})\s*-->\s*(\d{2}:\d{2}:\d{2},\d{3})/;

  for (let i = 0; i < 10; i++) {
    const chunkId = `chunk${String(i + 1).padStart(2, "0")}`;
    const offset = CHUNK_OFFSETS[i];
    const path = join(
      EXISTING_OUTPUT, chunkId, "with_srt", "intermediates", "transcripts", "part01_adjusted.txt"
    );
    if (!existsSync(path)) {
      console.error(`Missing transcript: ${path}`);
      continue;
    }

    const content = readFileSync(path, "utf-8");
    for (const line of content.split("\n")) {
      if (!line.trim()) continue;

      // Try HH:MM:SS,mmm --> HH:MM:SS,mmm format (adjusted transcripts)
      let match = line.match(hhmmssTimingRegex);
      if (match) {
        const relStart = tsToSecs(match[1]);
        const relEnd = tsToSecs(match[2]);
        const absStart = relStart + offset;
        const absEnd = relEnd + offset;
        const textPart = line.replace(match[0], "").replace(/^[\s\-\)]+/, "").trim();
        const absLine = `${secsToTs(absStart)} --> ${secsToTs(absEnd)} - ${textPart}`;
        allLines.push({ absoluteStart: absStart, absoluteEnd: absEnd, text: textPart, rawLine: absLine });
        continue;
      }

      // Try mm:ss - mm:ss format (raw transcripts)
      match = line.match(mmssTimingRegex);
      if (match) {
        const parseMmSs = (s: string) => {
          const [m, sec] = s.split(":").map(Number);
          return m * 60 + sec;
        };
        const relStart = parseMmSs(match[1]);
        const relEnd = parseMmSs(match[2]);
        const absStart = relStart + offset;
        const absEnd = relEnd + offset;
        const textPart = line.replace(match[0], "").replace(/^[\s\-\)]+/, "").replace(/^relative\s*\(/, "").trim();
        const absLine = `${secsToTs(absStart)} --> ${secsToTs(absEnd)} - ${textPart}`;
        allLines.push({ absoluteStart: absStart, absoluteEnd: absEnd, text: textPart, rawLine: absLine });
        continue;
      }

      // Non-timestamped line, include as-is
      if (line.trim().length > 0) {
        allLines.push({ absoluteStart: -1, absoluteEnd: -1, text: line.trim(), rawLine: line.trim() });
      }
    }
  }

  // Sort by absolute time
  allLines.sort((a, b) => a.absoluteStart - b.absoluteStart);
  return allLines;
}

// ── Build context windows ──────────────────────────────────────────────────

interface ContextWindow {
  label: string;
  transcript: string;
  srtContent: string;
  srtEntries: SrtEntry[];
  startTime: number;
  endTime: number;
}

function buildWindows(
  level: number,
  allTranscriptLines: TranscriptLine[],
  allSrt: SrtEntry[]
): ContextWindow[] {
  const totalStart = 0;
  const totalEnd = CHUNK_OFFSETS[CHUNK_OFFSETS.length - 1];
  const totalDuration = totalEnd - totalStart;

  const fullTranscript = allTranscriptLines.map((l) => l.rawLine).join("\n");

  if (level === 100) {
    return [
      {
        label: "100pct_full",
        transcript: fullTranscript,
        srtContent: srtEntriesToString(allSrt),
        srtEntries: allSrt,
        startTime: totalStart,
        endTime: totalEnd,
      },
    ];
  }

  const numWindows = Math.round(100 / level);
  const windowDuration = totalDuration / numWindows;
  const windows: ContextWindow[] = [];

  for (let w = 0; w < numWindows; w++) {
    const wStart = totalStart + w * windowDuration;
    const wEnd = totalStart + (w + 1) * windowDuration;

    // Filter transcript lines by absolute time
    const windowLines = allTranscriptLines.filter(
      (l) => l.absoluteStart >= 0 && l.absoluteStart >= wStart && l.absoluteStart < wEnd
    );
    const windowSrt = allSrt.filter(
      (e) => e.start >= wStart && e.start < wEnd
    );

    windows.push({
      label: `${level}pct_part${w + 1}of${numWindows}`,
      transcript: windowLines.map((l) => l.rawLine).join("\n"),
      srtContent: srtEntriesToString(windowSrt),
      srtEntries: windowSrt,
      startTime: wStart,
      endTime: wEnd,
    });
  }

  return windows;
}

// ── Call Gemini ─────────────────────────────────────────────────────────────

async function callGeminiTranslation(
  prompt: string,
  label: string
): Promise<string> {
  const apiKey = process.env.GEMINI_API_KEY;
  if (!apiKey) throw new Error("GEMINI_API_KEY not set");

  const ai = new GoogleGenAI({ apiKey });
  console.log(`  [${label}] Calling Gemini 2.5 Pro...`);
  const startTime = Date.now();

  let fullResponse = "";
  const response = await ai.models.generateContentStream({
    model: GEMINI_MODEL,
    config: { responseMimeType: "text/plain" },
    contents: [{ role: "user", parts: [{ text: prompt }] }],
  });

  for await (const chunk of response) {
    fullResponse += chunk.text;
  }

  const elapsed = ((Date.now() - startTime) / 1000).toFixed(1);
  console.log(
    `  [${label}] Done in ${elapsed}s (${fullResponse.length} chars)`
  );
  return fullResponse;
}

// ── Build prompt ───────────────────────────────────────────────────────────

function buildPrompt(transcript: string, srtContent: string, noSrt: boolean): string {
  let prompt = noSrt ? PROMPT_TEMPLATE_NOSRT : PROMPT_TEMPLATE;
  prompt = prompt.replace("{ADJUSTED_TRANSCRIPT}", transcript);
  if (!noSrt) {
    prompt = prompt.replace("{REFERENCE_SRT}", srtContent);
  }
  prompt = prompt.replace(/{SOURCE_LANGUAGE_NAME}/g, SOURCE_LANGUAGE);
  prompt = prompt.replace(/{TARGET_LANGUAGE_NAME}/g, TARGET_LANGUAGE);
  prompt = prompt.replace(/{TARGET_LANGUAGE_TAG}/g, TARGET_TAG);
  const xmlExample = `<${TARGET_TAG}_translation>[Your translation for ${TARGET_LANGUAGE}]</${TARGET_TAG}_translation>`;
  prompt = prompt.replace("{TARGET_LANGUAGE_XML_EXAMPLE}", xmlExample);
  return prompt;
}

// ── Parse response to SRT ──────────────────────────────────────────────────

function responseToSrt(responseText: string, label: string): string {
  const { entries, issues } = parseTranslationResponse(responseText, 1, [
    TARGET_LANGUAGE,
  ]);

  const errors = issues.filter((i) => i.severity === "error").length;
  const warnings = issues.filter((i) => i.severity === "warning").length;
  console.log(
    `  [${label}] Parsed ${entries.length} entries (${errors} errors, ${warnings} warnings)`
  );

  let srt = "";
  entries.forEach((entry, idx) => {
    const timing = entry.originalTiming || "00:00:00,000 --> 00:00:00,000";
    const english = entry.translations["english"] || entry.originalLine || "";
    const target = entry.translations[TARGET_LANGUAGE] || "";

    srt += `${idx + 1}\n`;
    srt += `${timing}\n`;
    srt += `<font color="#FFFFFF">${english}</font>\n`;
    srt += `<font color="#FFC0CB">${target}</font>\n\n`;
  });

  return srt;
}

// ── Main ───────────────────────────────────────────────────────────────────

const program = new Command();
program
  .name("context-sweep")
  .description("Translate with varying context window sizes (100%, 50%, 25%)")
  .option("-l, --level <levels>", "Comma-separated levels to run (default: 50,33,25)", "50,33,25")
  .option("--no-srt", "Run without reference SRT (blind translation from transcript only)")
  .parse();

const opts = program.opts();
const levels = opts.level.split(",").map(Number);
const noSrt = opts.srt === false; // --no-srt sets opts.srt to false

console.log("=".repeat(70));
console.log(`  Context Window Sweep${noSrt ? " (NO REFERENCE SRT)" : ""}`);
console.log("=".repeat(70));

// Load data
const allTranscriptLines = loadAllTranscriptLines();
console.log(`Loaded ${allTranscriptLines.length} transcript lines (absolute timestamps)`);
console.log(`  Time range: ${secsToTs(allTranscriptLines[0]?.absoluteStart ?? 0)} - ${secsToTs(allTranscriptLines[allTranscriptLines.length - 1]?.absoluteEnd ?? 0)}`);

const allSrt = parseSrtFull(REF_SRT_PATH);
console.log(`Loaded ${allSrt.length} reference SRT entries`);

const outputBase = noSrt ? SWEEP_OUTPUT_NOSRT : SWEEP_OUTPUT;
mkdirSync(outputBase, { recursive: true });

// Build all windows across all levels
interface Job {
  level: number;
  window: ContextWindow;
  prompt: string;
}

const jobs: Job[] = [];
for (const level of levels) {
  const windows = buildWindows(level, allTranscriptLines, allSrt);
  console.log(`\nLevel ${level}%: ${windows.length} window(s)`);
  for (const w of windows) {
    const prompt = buildPrompt(w.transcript, w.srtContent, noSrt);
    console.log(
      `  ${w.label}: ${w.srtEntries.length} ref subs, ${w.transcript.split("\n").length} transcript lines, prompt ${prompt.length} chars`
    );
    jobs.push({ level, window: w, prompt });
  }
}

// Run all jobs in parallel
console.log(`\nLaunching ${jobs.length} translation calls in parallel...`);

const results = await Promise.allSettled(
  jobs.map(async (job) => {
    const outDir = join(outputBase, `${job.level}pct`);
    mkdirSync(outDir, { recursive: true });

    // Skip if output already exists
    const srtPath = join(outDir, `${job.window.label}.bilingual.srt`);
    if (existsSync(srtPath)) {
      console.log(`  [${job.window.label}] SKIPPED (already exists: ${srtPath})`);
      return { label: job.window.label, srtPath, entryCount: -1 };
    }

    const responseText = await callGeminiTranslation(
      job.prompt,
      job.window.label
    );

    // Save raw response
    writeFileSync(
      join(outDir, `${job.window.label}_response.txt`),
      responseText
    );

    // Parse to SRT
    const srt = responseToSrt(responseText, job.window.label);
    const srtPath = join(outDir, `${job.window.label}.bilingual.srt`);
    writeFileSync(srtPath, srt);

    console.log(`  [${job.window.label}] Saved: ${srtPath}`);
    return { label: job.window.label, srtPath, entryCount: srt.split(/\n\n+/).filter(b => b.trim()).length };
  })
);

// Summary
console.log("\n" + "=".repeat(70));
console.log("  Results");
console.log("=".repeat(70));
for (const r of results) {
  if (r.status === "fulfilled") {
    console.log(`  OK: ${r.value.label} (${r.value.entryCount} entries) -> ${r.value.srtPath}`);
  } else {
    console.log(`  FAIL: ${r.reason}`);
  }
}

console.log(`\nOutput at: ${outputBase}/`);

