  1→#!/usr/bin/env bun
  2→
  3→import { join } from "path";
  4→import { existsSync } from "fs";
  5→import { Command } from "commander";
  6→import chalk from "chalk";
  7→import type { ChunkInfo, ProcessingIssue } from "../types.js";
  8→import {
  9→  configureLogger,
 10→  info,
 11→  warn,
 12→  error,
 13→  success,
 14→} from "../utils/logger.js";
 15→import { ensureDir } from "../utils/file_utils.js";
 16→import { splitVideo, getVideoDuration } from "./video_splitter.js";
 17→import { splitSrt } from "./srt_splitter.js";
 18→import { calculateChunks, type TimeChunk } from "../utils/time_utils.js";
 19→
 20→interface SplitterOptions {
 21→  videoPath: string;
 22→  srtPath?: string;
 23→  outputDir: string;
 24→  chunkDuration: number;
 25→  chunkOverlap: number;
 26→  chunkFormat: "mp3" | "mp4";
 27→  maxConcurrent: number;
 28→  force: boolean;
 29→  processOnlyPart?: number;
 30→  inputOffsetSeconds?: number;
 31→}
 32→
 33→/**
 34→ * Main function to split media and optionally SRT
 35→ */
 36→export async function split(
 37→  options: SplitterOptions
 38→): Promise<{ chunks: ChunkInfo[]; issues: ProcessingIssue[] }> {
 39→  const {
 40→    videoPath,
 41→    srtPath,
 42→    outputDir,
 43→    chunkDuration,
 44→    chunkOverlap,
 45→    chunkFormat,
 46→    maxConcurrent,
 47→    force,
 48→    processOnlyPart,
 49→    inputOffsetSeconds,
 50→  } = options;
 51→
 52→  // Validate inputs
 53→  if (!existsSync(videoPath)) {
 54→    error(`Video file does not exist: ${videoPath}`);
 55→    return {
 56→      chunks: [],
 57→      issues: [
 58→        {
 59→          type: "SplitError",
 60→          severity: "error",
 61→          message: "Video file not found",
 62→        },
 63→      ],
 64→    };
 65→  }
 66→
 67→  if (srtPath && !existsSync(srtPath)) {
 68→    warn(`SRT file does not exist: ${srtPath}`);
 69→  }
 70→
 71→  // Create output directories
 72→  const mediaDir = join(outputDir, "media");
 73→  const srtDir = join(outputDir, "srt");
 74→
 75→  ensureDir(mediaDir);
 76→  if (srtPath) {
 77→    ensureDir(srtDir);
 78→  }
 79→
 80→  // Split video
 81→  info(`Splitting video: ${videoPath}`);
 82→  info(
 83→    `Chunk settings: ${chunkDuration}s duration, ${chunkOverlap}s overlap, ${chunkFormat} format`
 84→  );
 85→
 86→  // Get duration first to calculate chunks
 87→  const duration = await getVideoDuration(videoPath);
 88→  if (!duration) {
 89→    error(`Failed to get video duration for ${videoPath}`);
 90→    return {
 91→      chunks: [],
 92→      issues: [
 93→        {
 94→          type: "SplitError",
 95→          severity: "error",
 96→          message: "Failed to get video duration",
 97→        },
 98→      ],
 99→    };
100→  }
101→
102→  // Calculate ALL potential time chunks
103→  const allTimeChunks = calculateChunks(duration, chunkDuration, chunkOverlap);
104→  let timeChunksToProcess: TimeChunk[] = allTimeChunks;
105→  info(`Calculated ${allTimeChunks.length} potential chunks.`);
106→
107→  // Filter time chunks if only processing a specific part
108→  if (processOnlyPart !== undefined) {
109→    timeChunksToProcess = allTimeChunks.filter(
110→      (tc: TimeChunk) => tc.partNumber === processOnlyPart
111→    );
112→    if (timeChunksToProcess.length === 0) {
113→      error(
114→        `Part number ${processOnlyPart} is out of the calculated range (1-${allTimeChunks.length}).`
115→      );
116→      return {
117→        chunks: [],
118→        issues: [
119→          {
120→            type: "SplitError",
121→            severity: "error",
122→            message: `Invalid part number ${processOnlyPart}`,
123→          },
124→        ],
125→      };
126→    }
127→    info(`Filtering to process only part ${processOnlyPart}.`);
128→  }
129→
130→  // Now call splitVideo with the potentially filtered timeChunks (or all if no specific part)
131→  const { chunks, issues } = await splitVideo(
132→    videoPath,
133→    mediaDir,
134→    chunkFormat,
135→    maxConcurrent,
136→    timeChunksToProcess,
137→    { force: force }
138→  );
139→
140→  // If we have an SRT file, split it too
141→  if (srtPath && existsSync(srtPath)) {
142→    info(`Splitting SRT: ${srtPath}`);
143→    // Log the actual value to help debug
144→    info(
145→      `Using input offset: ${
146→        inputOffsetSeconds !== undefined ? inputOffsetSeconds : 0
147→      }s`
148→    );
149→    const srtResult = await splitSrt(
150→      srtPath,
151→      chunks,
152→      srtDir,
153→      force,
154→      inputOffsetSeconds ?? 0
155→    );
156→    issues.push(...srtResult.issues);
157→  }
158→
159→  // Log summary
160→  const successCount = chunks.filter((c) => c.status !== "failed").length;
161→  const failCount = timeChunksToProcess.length - successCount;
162→
163→  if (failCount === 0) {
164→    success(
165→      `Splitting complete: ${successCount} chunk(s) created successfully for part ${
166→        processOnlyPart ?? "all"
167→      }`
168→    );
169→  } else {
170→    warn(
171→      `Splitting complete with issues: ${successCount} successful, ${failCount} failed for part ${
172→        processOnlyPart ?? "all"
173→      }`
174→    );
175→  }
176→
177→  return { chunks, issues };
178→}
179→
180→/**
181→ * CLI entry point
182→ */
183→async function main() {
184→  const program = new Command();
185→
186→  program
187→    .name("subtitle-splitter")
188→    .description("Split video and subtitle files into chunks")
189→    .version("1.0.0")
190→    .requiredOption("-v, --video <path>", "Path to video file")
191→    .option("-s, --srt <path>", "Path to SRT subtitle file")
192→    .option("-o, --output <dir>", "Output directory", "./output")
193→    .option("-d, --duration <seconds>", "Chunk duration in seconds", "1200")
194→    .option("-l, --overlap <seconds>", "Chunk overlap in seconds", "300")
195→    .option("-f, --format <format>", "Chunk format (mp3 or mp4)", "mp3")
196→    .option("-c, --concurrent <number>", "Max concurrent processes", "5")
197→    .option("--force", "Force overwrite existing files", false)
198→    .option("--log-file <path>", "Path to log file")
199→    .option(
200→      "--log-level <level>",
201→      "Log level (debug, info, warn, error)",
202→      "info"
203→    )
204→    .option("-P, --part <number>", "Process only a specific part number")
205→    .option(
206→      "--input-offset <seconds>",
207→      "Apply offset (in seconds, can be negative) to input SRT timings"
208→    )
209→    .parse();
210→
211→  const opts = program.opts();
212→
213→  // Configure logger
214→  configureLogger({
215→    logToFile: !!opts.logFile,
216→    logFilePath: opts.logFile,
217→    consoleLogLevel: opts.logLevel || "info",
218→  });
219→
220→  try {
221→    const options: SplitterOptions = {
222→      videoPath: opts.video,
223→      srtPath: opts.srt,
224→      outputDir: opts.output,
225→      chunkDuration: parseInt(opts.duration),
226→      chunkOverlap: parseInt(opts.overlap),
227→      chunkFormat: opts.format === "mp4" ? "mp4" : "mp3",
228→      maxConcurrent: parseInt(opts.concurrent),
229→      force: opts.force,
230→      processOnlyPart: opts.part ? parseInt(opts.part) : undefined,
231→      inputOffsetSeconds: opts.inputOffset
232→        ? parseFloat(opts.inputOffset)
233→        : undefined,
234→    };
235→
236→    const { chunks, issues } = await split(options);
237→
238→    // Log issues
239→    if (issues.length > 0) {
240→      warn(`Encountered ${issues.length} issues:`);
241→      issues.forEach((issue) => {
242→        const prefix =
243→          issue.severity === "error"
244→            ? chalk.red("ERROR")
245→            : chalk.yellow("WARNING");
246→        console.log(`${prefix}: ${issue.message}`);
247→      });
248→    }
249→
250→    // Save chunk info for downstream processing
251→    const outputInfoPath = join(options.outputDir, "chunk_info.json");
252→    const fs = await import("fs/promises");
253→    await fs.writeFile(outputInfoPath, JSON.stringify(chunks, null, 2));
254→    info(`Chunk info saved to: ${outputInfoPath}`);
255→
256→    process.exit(issues.some((i) => i.severity === "error") ? 1 : 0);
257→  } catch (err: any) {
258→    error(`Fatal error: ${err.message || err}`, err.stack);
259→    process.exit(1);
260→  }
261→}
262→
263→// Run main if called directly (only when running this file standalone with Bun)
264→if (typeof Bun !== 'undefined' && import.meta.url.replace("file://", "") === Bun.main) {
265→  main();
266→}
