  1→import { spawn } from "child_process";
  2→import { join, basename } from "path";
  3→// Use type-only import for types
  4→import type { ChunkInfo, ProcessingIssue, Config } from "../types.js";
  5→// Import secondsToTimestamp value, and TimeChunk type
  6→import { secondsToTimestamp, type TimeChunk } from "../utils/time_utils.js";
  7→import { ensureDir } from "../utils/file_utils.js";
  8→import * as logger from "../utils/logger.js";
  9→import cliProgress from "cli-progress";
 10→import chalk from "chalk";
