  1→#!/usr/bin/env bun
  2→
  3→import { join, basename } from "path";
  4→import { existsSync } from "fs";
  5→import { Command } from "commander";
  6→import chalk from "chalk";
  7→import cliProgress from "cli-progress";
  8→import type { ChunkInfo, Config, ProcessingIssue } from "../types";
  9→import * as logger from "../utils/logger";
 10→import { ensureDir, writeToFile, readJsonFromFile } from "../utils/file_utils";
 11→import { transcribeChunk } from "./gemini_transcriber";
 12→import { adjustTranscriptTimestamps } from "../utils/transcript_utils";
 13→import boxen from "boxen";
 14→
 15→/**
 16→ * Transcribes multiple media chunks based on ChunkInfo.
 17→ *
 18→ * @param chunks Array of ChunkInfo objects (from splitter).
 19→ * @param config Pipeline configuration.
 20→ * @returns Promise resolving to updated chunks and any issues encountered.
 21→ */
 22→export async function transcribe(
 23→  chunks: ChunkInfo[],
 24→  config: Config
 25→): Promise<{ chunks: ChunkInfo[]; issues: ProcessingIssue[] }> {
 26→  const issues: ProcessingIssue[] = [];
 27→
 28→  // Define directory paths
 29→  const transcriptDir = join(config.intermediateDir, "transcripts");
 30→  const rawTranscriptDir = join(config.intermediateDir, "raw_llm_transcripts");
 31→  ensureDir(transcriptDir); // For adjusted transcripts
 32→  ensureDir(rawTranscriptDir); // For raw LLM output
 33→
 34→  // --- Identify Chunks Requiring Actual Processing ---
 35→  const chunksNeedingProcessing: ChunkInfo[] = [];
 36→  const chunksToSkip: ChunkInfo[] = [];
 37→
 38→  for (const chunk of chunks) {
 39→    const mediaPath = chunk.mediaChunkPath;
 40→    if (!mediaPath || !existsSync(mediaPath)) {
 41→      logger.warn(
 42→        `[Chunk ${chunk.partNumber}] Skipping transcription: Input media file missing (${mediaPath}).`
 43→      );
 44→      // Keep its existing status or mark as failed?
 45→      if (chunk.status !== "failed") chunk.status = "failed"; // Mark failed if input missing
 46→      chunk.error = `Input media missing: ${mediaPath}`;
 47→      issues.push({
 48→        type: "TranscriptionError",
 49→        severity: "error",
 50→        message: chunk.error,
 51→        chunkPart: chunk.partNumber,
 52→      });
 53→      chunksToSkip.push(chunk); // Add to skip list for clarity
 54→      continue; // Skip this chunk
 55→    }
 56→
 57→    if (config.force) {
 58→      logger.debug(
 59→        `[Chunk ${chunk.partNumber}] Force processing enabled for transcription.`
 60→      );
 61→      chunksNeedingProcessing.push(chunk);
 62→      continue;
 63→    }
 64→
 65→    const adjustedPath =
 66→      chunk.adjustedTranscriptPath ||
 67→      join(
 68→        transcriptDir,
 69→        `part${chunk.partNumber.toString().padStart(2, "0")}_adjusted.txt`
 70→      );
 71→
 72→    if (existsSync(adjustedPath)) {
 73→      if (chunk.status === "failed") {
 74→        logger.debug(
 75→          `[Chunk ${chunk.partNumber}] Output exists, but reprocessing due to failed status.`
 76→        );
 77→        chunksNeedingProcessing.push(chunk);
 78→      } else {
 79→        logger.debug(
 80→          `[Chunk ${chunk.partNumber}] Skipping transcription: Adjusted transcript already exists (${adjustedPath}) and status is not 'failed'.`
 81→        );
 82→        // *** IMPORTANT: Populate path and set status ***
 83→        chunk.adjustedTranscriptPath = adjustedPath;
 84→        if (chunk.status !== "completed" && chunk.status !== "prompting") {
 85→          chunk.status = "prompting"; // Assume successful if output exists and not failed
 86→        }
 87→        chunksToSkip.push(chunk); // Add to skip list
 88→      }
 89→    } else {
 90→      logger.debug(
 91→        `[Chunk ${chunk.partNumber}] Output adjusted transcript missing. Processing.`
 92→      );
 93→      chunksNeedingProcessing.push(chunk);
 94→    }
 95→  }
 96→
 97→  // Filter based on processOnlyPart *after* initial checks
 98→  let finalChunksToProcess = chunksNeedingProcessing;
 99→  if (config.processOnlyPart !== undefined) {
100→    finalChunksToProcess = chunksNeedingProcessing.filter(
101→      (c) => c.partNumber === config.processOnlyPart
102→    );
103→    // Also filter skip list if only processing one part, though less critical
104→    // chunksToSkip = chunksToSkip.filter(c => c.partNumber === config.processOnlyPart);
105→  }
106→
107→  if (finalChunksToProcess.length === 0) {
108→    logger.info(
109→      "No chunks require active transcription processing (based on status, file existence, and part filter)."
110→    );
111→    // Return the original chunks array, as its stati were updated for skipped items
112→    return { chunks, issues };
113→  }
114→
115→  if (!config.apiKeys.gemini) {
116→    logger.error("Missing Gemini API key..."); /* ... */
117→    // Mark ONLY the chunks we were trying to process as failed
118→    finalChunksToProcess.forEach((c) => {
119→      c.status = "failed";
120→      c.error = "Missing Gemini API key";
121→    });
122→    return { chunks, issues }; // Return the full chunk list with updated stati
123→  }
124→
125→  logger.info(
126→    `Attempting to transcribe/reprocess ${finalChunksToProcess.length} chunks using ${config.transcriptionModel}...`
127→  );
128→
129→  // --- Progress Bar Setup (Based on count needing processing) ---
130→  const startTime = Date.now();
131→  let intervalId: Timer | null = null;
132→  const multibar = new cliProgress.MultiBar(
133→    {
134→      clearOnComplete: false,
135→      hideCursor: true,
136→      format: `${chalk.cyan(
137→        "{bar}"
138→      )} | {percentage}% | {value}/{total} Chunks | ETA: {eta_formatted} | Elapsed: {elapsed}s | ${chalk.gray(
139→        "{task}"
140→      )}`,
141→    },
142→    cliProgress.Presets.shades_classic
143→  );
144→  const progressBar = multibar.create(finalChunksToProcess.length, 0, {
145→    task: "Starting transcription...",
146→    elapsed: "0.0",
147→  });
148→  logger.setActiveMultibar(multibar);
149→
150→  // Update timer to 100ms
151→  intervalId = setInterval(() => {
152→    const elapsedSeconds = ((Date.now() - startTime) / 1000).toFixed(1);
153→    progressBar.update({ elapsed: elapsedSeconds });
154→  }, 100);
155→
156→  // --- Concurrency Control (Operate on finalChunksToProcess) ---
157→  const queue = [...finalChunksToProcess]; // Use the filtered list
158→  const maxConcurrent =
159→    config.maxConcurrent > 0 ? config.maxConcurrent : queue.length;
160→  const activePromises: Promise<void>[] = [];
161→  let processedCount = 0;
162→
163→  const startNextTranscribeTask = () => {
164→    if (queue.length === 0) return;
165→    const chunk = queue.shift(); // Get chunk from the filtered queue
166→    if (!chunk) return;
167→
168→    // Reset status for this attempt (important for retries)
169→    chunk.status = "transcribing";
170→    chunk.error = undefined;
171→    // Clear paths that will be reset on success/failure
172→    chunk.rawTranscriptPath = undefined;
173→    chunk.adjustedTranscriptPath = undefined;
174→    chunk.failedTranscriptPath = undefined;
175→
176→    progressBar.update(processedCount, {
177→      task: `Transcribing chunk ${chunk.partNumber}...`,
178→    });
179→
180→    const taskPromise = (async () => {
181→      // Call transcribeChunk, which handles validation/retries internally
182→      const { transcript: rawTranscript, issues: chunkIssues } =
183→        await transcribeChunk(chunk, config);
184→      issues.push(...chunkIssues); // Add issues from this specific chunk processing
185→
186→      if (rawTranscript !== null) {
187→        // *** Success Path ***
188→        const rawFileName = `part${chunk.partNumber
189→          .toString()
190→          .padStart(2, "0")}_raw.txt`;
191→        chunk.rawTranscriptPath = join(rawTranscriptDir, rawFileName);
192→        await writeToFile(chunk.rawTranscriptPath, rawTranscript);
193→        // ... (Adjust timestamps) ...
194→        const adjustedTranscript = adjustTranscriptTimestamps(
195→          rawTranscript,
196→          chunk.startTimeSeconds
197→        );
198→        // ... (Save adjusted) ...
199→        const adjustedFileName = `part${chunk.partNumber
200→          .toString()
201→          .padStart(2, "0")}_adjusted.txt`;
202→        chunk.adjustedTranscriptPath = join(transcriptDir, adjustedFileName);
203→        await writeToFile(chunk.adjustedTranscriptPath, adjustedTranscript);
204→        chunk.status = "prompting";
205→        logger.debug(`Successfully processed chunk ${chunk.partNumber}`);
206→      } else {
207→        // *** Failure Path (API error or validation failure after retries) ***
208→        chunk.status = "failed";
209→        chunk.error =
210→          chunk.error || "Transcription/Validation failed after retries";
211→        logger.warn(
212→          `[Chunk ${chunk.partNumber}] Failed transcription/validation.`
213→        );
214→      }
215→    })()
216→      .catch((error: any) => {
217→        if (chunk) {
218→          chunk.status = "failed";
219→          chunk.error = `Unexpected error during chunk ${
220→            chunk.partNumber
221→          } transcription/adjustment: ${error.message || error}`;
222→          logger.error(
223→            `[Chunk ${chunk.partNumber}] ${chunk.error}`,
224→            error.stack
225→          );
226→          issues.push({
227→            type: "TranscriptionError",
228→            severity: "error",
229→            message: chunk.error,
230→            chunkPart: chunk.partNumber,
231→            context: error.stack,
232→          });
233→        } else {
234→          logger.error(
235→            `Unexpected error during transcription processing (chunk undefined): ${
236→              error.message || error
237→            }`,
238→            error.stack
239→          );
240→          issues.push({
241→            type: "TranscriptionError",
242→            severity: "error",
243→            message: `Unexpected transcription error: ${
244→              error.message || error
245→            }`,
246→            context: error.stack,
247→          });
248→        }
249→      })
250→      .finally(() => {
251→        processedCount++;
252→        progressBar.update(processedCount, {
253→          // Use update instead of increment for clarity
254→          task:
255→            chunk.status === "failed"
256→              ? `Chunk ${chunk.partNumber} failed!`
257→              : `Chunk ${chunk.partNumber} done.`,
258→        });
259→        const index = activePromises.indexOf(taskPromise);
260→        if (index > -1) activePromises.splice(index, 1);
261→        if (activePromises.length < maxConcurrent) startNextTranscribeTask();
262→      });
263→    activePromises.push(taskPromise);
264→  };
265→
266→  // --- Start processing loop ---
267→  for (let i = 0; i < Math.min(maxConcurrent, queue.length); i++) {
268→    startNextTranscribeTask();
269→  }
270→  while (activePromises.length > 0 || queue.length > 0) {
271→    while (activePromises.length < maxConcurrent && queue.length > 0) {
272→      startNextTranscribeTask();
273→    }
274→    if (activePromises.length > 0) {
275→      await Promise.race(activePromises);
276→    }
277→  }
278→
279→  // --- Cleanup ---
280→  if (intervalId) clearInterval(intervalId); // Clear timer
281→  progressBar.stop();
282→  multibar.stop();
283→  logger.setActiveMultibar(null);
284→
285→  // --- Final Summary ---
286→  const successCount = finalChunksToProcess.filter(
287→    (c) => c.status === "prompting"
288→  ).length; // Check against processed list
289→  logger.info(
290→    `Transcription & Adjustment complete: ${successCount} / ${finalChunksToProcess.length} chunks actively processed.`
291→  );
292→
293→  // --- IMPORTANT: Return the original full chunks array, which has updated stati ---
294→  return { chunks, issues };
295→}
