299→interface TranscriberCliOptions {
300→  chunkInfoPath: string;
301→  intermediateDir: string; // Needed to construct transcript output path
302→  transcriptionModel?: string;
303→  geminiApiKey?: string;
304→  maxConcurrent?: number;
