  1→#!/usr/bin/env bun
  2→
  3→import { join } from "path";
  4→import { existsSync } from "fs";
  5→import { Command } from "commander";
  6→import chalk from "chalk";
  7→import cliProgress from "cli-progress";
  8→import boxen from "boxen";
  9→import type { ChunkInfo, Config, ProcessingIssue } from "../types.js";
 10→import * as logger from "../utils/logger.js";
 11→import {
 12→  ensureDir,
 13→  writeToFile,
 14→  readJsonFromFile,
 15→  readFromFile,
 16→} from "../utils/file_utils.js";
 17→import { generateTranslationPrompt } from "./prompt_generator.js";
 18→import { callGemini, type GeminiCallResult } from "./gemini_translator.js";
 19→import { callClaude, type ClaudeCallResult } from "./claude_translator.js";
 20→import { parseTranslationResponse } from "../parser/response_parser.js";
 21→import { validateTranslations } from "../validator/translation_validator.js";
 22→
 23→// Helper function for exponential backoff
 24→const delay = (ms: number) => new Promise((resolve) => setTimeout(resolve, ms));
 25→
 26→// Structure to hold data across retries
 27→interface FailedAttemptData {
 28→  attemptNum: number;
 29→  responseText: string;
 30→  validationIssues: ProcessingIssue[];
 31→  parsingIssues: ProcessingIssue[];
 32→}
 33→
 34→/**
 35→ * Processes a single chunk: generates prompt, calls LLM, handles retries (API & Validation), parses, validates, saves results.
 36→ * Includes special handling for the last chunk on final validation attempt.
 37→ */
 38→async function processTranslationChunk(
 39→  chunk: ChunkInfo,
 40→  config: Config,
 41→  issues: ProcessingIssue[],
 42→  isLastChunk: boolean,
 43→  // Pass accumulated failed data through recursive calls
 44→  failedAttemptsData: FailedAttemptData[] = [],
 45→  attemptNum: number = 1
 46→): Promise<void> {
 47→  const llmLogsDir = join(config.intermediateDir, "llm_logs");
 48→  const responsesDir = join(config.intermediateDir, "llm_responses");
 49→  const parsedDir = join(config.intermediateDir, "parsed_data");
 50→  ensureDir(llmLogsDir);
 51→  ensureDir(responsesDir);
 52→  ensureDir(parsedDir);
 53→
 54→  // 1. Generate Prompt (Only needs to happen once per chunk unless retrying the LLM call)
 55→  // Store prompt locally in case we need to retry the LLM call
 56→  let prompt: string | null = null;
 57→  if (attemptNum === 1) {
 58→    // Only generate on first attempt
 59→    prompt = await generateTranslationPrompt(chunk, config);
 60→    if (!prompt) {
 61→      chunk.status = "failed";
 62→      chunk.error = "Failed to generate translation prompt.";
 63→      issues.push({
 64→        type: "PromptGenError",
 65→        severity: "error",
 66→        message: chunk.error,
 67→        chunkPart: chunk.partNumber,
 68→      });
 69→      logger.error(`[Chunk ${chunk.partNumber}] ${chunk.error}`);
 70→      return;
 71→    }
 72→    const requestLogPath = join(
 73→      llmLogsDir,
 74→      `part${chunk.partNumber
 75→        .toString()
 76→        .padStart(2, "0")}_request_attempt${attemptNum}.json`
 77→    );
 78→    await writeToFile(requestLogPath, {
 79→      timestamp: new Date().toISOString(),
 80→      model: config.translationModel,
 81→      prompt,
 82→    });
 83→    chunk.llmRequestLogPath = requestLogPath; // Store latest request path
 84→  } else {
 85→    // On retry, try to reload the previously generated prompt
 86→    const previousRequestPath = join(
 87→      llmLogsDir,
 88→      `part${chunk.partNumber
 89→        .toString()
 90→        .padStart(2, "0")}_request_attempt1.json`
 91→    );
 92→    if (existsSync(previousRequestPath)) {
 93→      try {
 94→        const reqData = await readJsonFromFile<any>(previousRequestPath);
 95→        prompt = reqData?.prompt;
 96→      } catch (e) {
 97→        /* ignore if read fails */
 98→      }
 99→    }
100→    if (!prompt) {
101→      chunk.status = "failed";
102→      chunk.error = "Failed to retrieve prompt for retry.";
103→      issues.push({
104→        type: "PromptGenError",
105→        severity: "error",
106→        message: chunk.error,
107→        chunkPart: chunk.partNumber,
108→      });
109→      logger.error(`[Chunk ${chunk.partNumber}] ${chunk.error}`);
110→      return;
111→    }
112→    logger.info(
113→      `[Chunk ${chunk.partNumber}] Using previously generated prompt for validation retry.`
114→    );
115→  }
116→
117→  // 2. Call LLM with API Retries (Use general config.retries)
118→  let callResult: ClaudeCallResult | GeminiCallResult | null = null; // Updated type
119→  const maxApiRetries = config.retries ?? 2;
120→  for (let apiAttempt = 1; apiAttempt <= maxApiRetries + 1; apiAttempt++) {
121→    chunk.status = "translating";
122→    logger.debug(
123→      `[Chunk ${chunk.partNumber}] LLM Call Attempt ${apiAttempt}/${
124→        maxApiRetries + 1
125→      }`
126→    );
127→    let currentRawResponse: string | null = null;
128→    chunk.llmTranslationInputTokens = undefined; // Reset tokens for this attempt
129→    chunk.llmTranslationOutputTokens = undefined;
130→
131→    try {
132→      if (config.translationModel.toLowerCase().includes("claude")) {
133→        callResult = await callClaude(prompt!, config, chunk);
134→        if (callResult) {
135→          currentRawResponse = callResult.responseText;
136→          chunk.llmTranslationInputTokens = callResult.inputTokens;
137→          chunk.llmTranslationOutputTokens = callResult.outputTokens;
138→        } else {
139→          currentRawResponse = null; // Ensure null if callClaude returns null
140→        }
141→      } else {
142→        callResult = await callGemini(prompt!, config, chunk);
143→        if (callResult) {
144→          currentRawResponse = callResult.responseText;
145→          chunk.llmTranslationInputTokens = callResult.inputTokens;
146→          chunk.llmTranslationOutputTokens = callResult.outputTokens;
147→        } else {
148→          currentRawResponse = null; // Ensure null if callGemini returns null
149→        }
150→      }
151→
152→      if (currentRawResponse !== null) {
153→        // Check if we got text
154→        logger.debug(
155→          `[Chunk ${chunk.partNumber}] Received successful response text on attempt ${apiAttempt}.`
156→        );
157→        break; // Success, exit retry loop
158→      }
159→      logger.warn(
160→        `[Chunk ${chunk.partNumber}] LLM call attempt ${apiAttempt} failed (returned null text).`
161→      );
162→    } catch (error: any) {
163→      logger.error(
164→        `[Chunk ${
165→          chunk.partNumber
166→        }] Unexpected error during LLM call attempt ${apiAttempt}: ${
167→          error.message || error
168→        }`
169→      );
170→      callResult = null; // Ensure null on unexpected error
171→    }
172→    if (apiAttempt <= maxApiRetries) {
173→      const waitTime = Math.pow(2, apiAttempt) * 1000;
174→      logger.info(
175→        `[Chunk ${chunk.partNumber}] Retrying LLM call in ${
176→          waitTime / 1000
177→        }s...`
178→      );
179→      await delay(waitTime);
180→    } else {
181→      logger.error(
182→        `[Chunk ${chunk.partNumber}] LLM call failed after ${
183→          maxApiRetries + 1
184→        } API attempts.`
185→      );
186→    }
187→  }
188→
189→  // 3. Handle LLM Call Outcome (check callResult for overall success)
190→  if (callResult === null || callResult.responseText === null) {
191→    chunk.status = "failed";
192→    chunk.error =
193→      chunk.error || `LLM call failed after ${maxApiRetries + 1} attempts.`;
194→    issues.push({
195→      type: "TranslationError",
196→      severity: "error",
197→      message: chunk.error,
198→      chunkPart: chunk.partNumber,
199→    });
200→    return; // Cannot proceed without a response
201→  }
202→
203→  const rawResponse = callResult.responseText; // We have a valid response text now
204→
205→  // --- Save raw response ---
206→  const responseFileName = `part${chunk.partNumber
207→    .toString()
208→    .padStart(2, "0")}_response_attempt${attemptNum}.txt`;
209→  chunk.responsePath = join(responsesDir, responseFileName);
210→  await writeToFile(chunk.responsePath, rawResponse);
211→  // TODO: Log structured response if possible (callResult might contain more for Claude)
212→
213→  // 4. Parse Response
214→  logger.info(
215→    `[Chunk ${chunk.partNumber}] Parsing LLM response (Attempt ${attemptNum})...`
216→  );
217→  const { entries: parsedEntries, issues: parsingIssues } =
218→    parseTranslationResponse(
219→      rawResponse,
220→      chunk.partNumber,
221→      config.targetLanguages
222→    );
223→  // Add parsing issues to the main list AND store them for this attempt
224→  issues.push(...parsingIssues);
225→  const currentAttemptParsingIssues = parsingIssues;
226→
227→  // 5. Validate Parsed Response
228→  logger.info(
229→    `[Chunk ${chunk.partNumber}] Validating parsed response (Attempt ${attemptNum})...`
230→  );
231→  const maxValidationRetries = config.retries ?? 1;
232→  const isFinalValidationAttempt = attemptNum >= maxValidationRetries + 1;
233→  const { isValid: isTranslationValid, validationIssues } =
234→    await validateTranslations(
235→      chunk.partNumber,
236→      parsedEntries,
237→      currentAttemptParsingIssues,
238→      chunk.srtChunkPath,
239→      config,
240→      isLastChunk,
241→      isFinalValidationAttempt // Pass flag indicating if this is the last chance
242→    );
243→  // Add validation issues to the main list AND store them for this attempt
244→  issues.push(...validationIssues);
245→  const currentAttemptValidationIssues = validationIssues;
246→
247→  // 6. Handle Validation Outcome & Validation Retries
248→  if (isTranslationValid) {
249→    // --- Validation Success ---
250→    logger.info(
251→      `[Chunk ${chunk.partNumber}] Translation passed validation (Attempt ${attemptNum}).`
252→    );
253→    // Save parsed data
254→    const parsedFileName = `part${chunk.partNumber
255→      .toString()
256→      .padStart(2, "0")}_parsed.json`;
257→    chunk.parsedDataPath = join(parsedDir, parsedFileName);
258→    const saveSuccess = await writeToFile(chunk.parsedDataPath, parsedEntries);
259→    if (saveSuccess) {
260→      chunk.status = "completed";
261→    } else {
262→      chunk.status = "failed";
263→      chunk.error = `Failed to save parsed data to ${chunk.parsedDataPath}`;
264→      // Ensure this critical save failure is logged as an error issue
265→      const saveErrorIssue: ProcessingIssue = {
266→        type: "FormatError",
267→        severity: "error",
268→        message: chunk.error,
269→        chunkPart: chunk.partNumber,
270→      };
271→      issues.push(saveErrorIssue);
272→      logger.error(`[Chunk ${chunk.partNumber}] ${chunk.error}`);
273→    }
274→  } else {
275→    // --- Validation Failure (at least one error severity issue found) ---
276→    // Log the specific validation errors that caused the failure
277→    const errorMessages = validationIssues
278→      .filter((vi) => vi.severity === "error")
279→      .map((vi) => vi.message)
280→      .join("; ");
281→    logger.warn(
282→      `[Chunk ${
283→        chunk.partNumber
284→      }] Translation failed validation on attempt ${attemptNum}. Reason(s): ${
285→        errorMessages || "See logs"
286→      }`
287→    );
288→
289→    // Store the current attempt's data for potential fallback
290→    failedAttemptsData.push({
291→      attemptNum,
292→      responseText: rawResponse,
293→      validationIssues: currentAttemptValidationIssues,
294→      parsingIssues: currentAttemptParsingIssues,
295→    });
296→
297→    if (attemptNum > maxValidationRetries) {
298→      // All validation retries exhausted
299→      logger.error(
300→        `[Chunk ${chunk.partNumber}] Translation failed validation after ${attemptNum} attempts.`
301→      );
302→
303→      // Special handling for last chunk - use the longest response if this is the last chunk
304→      if (isLastChunk && failedAttemptsData.length > 0) {
305→        logger.warn(
306→          `[Chunk ${chunk.partNumber}] This is the last chunk and all validation attempts failed. Finding longest usable response...`
307→        );
308→
309→        // Find the response with the most successfully parsed entries
310→        let bestAttempt = failedAttemptsData[0];
311→        let maxEntryCount = parsedEntries.length;
312→
313→        for (const attempt of failedAttemptsData) {
314→          const attemptEntries = parseTranslationResponse(
315→            attempt.responseText,
316→            chunk.partNumber,
317→            config.targetLanguages
318→          ).entries;
319→
320→          if (attemptEntries.length > maxEntryCount) {
321→            maxEntryCount = attemptEntries.length;
322→            bestAttempt = attempt;
323→          }
324→        }
325→
326→        logger.info(
327→          `[Chunk ${chunk.partNumber}] Using best failed attempt (attempt ${bestAttempt.attemptNum}) with ${maxEntryCount} entries as fallback.`
328→        );
329→
330→        // Re-parse the best attempt
331→        const bestParsedResponse = parseTranslationResponse(
332→          bestAttempt.responseText,
333→          chunk.partNumber,
334→          config.targetLanguages
335→        );
336→
337→        // Save the best attempt's parsed data
338→        const parsedFileName = `part${chunk.partNumber
339→          .toString()
340→          .padStart(2, "0")}_parsed.json`;
341→        chunk.parsedDataPath = join(parsedDir, parsedFileName);
342→        const saveSuccess = await writeToFile(
343→          chunk.parsedDataPath,
344→          bestParsedResponse.entries
345→        );
346→
347→        if (saveSuccess) {
348→          chunk.status = "completed";
349→          logger.info(
350→            `[Chunk ${chunk.partNumber}] Saved fallback response for the last chunk.`
351→          );
352→        } else {
353→          chunk.status = "failed";
354→          chunk.error = `Failed to save parsed data to ${chunk.parsedDataPath}`;
355→          issues.push({
356→            type: "FormatError",
357→            severity: "error",
358→            message: chunk.error,
359→            chunkPart: chunk.partNumber,
360→          });
361→          logger.error(`[Chunk ${chunk.partNumber}] ${chunk.error}`);
362→        }
363→      } else {
364→        // Not the last chunk or no failed attempts data available
365→        chunk.status = "failed";
366→        chunk.error =
367→          chunk.error ||
368→          `Validation failed after ${attemptNum} attempts: ${
369→            errorMessages || "Unknown"
370→          }`;
371→        // Ensure a final error issue is present if somehow missed
372→        if (
373→          !issues.some(
374→            (i) =>
375→              i.chunkPart === chunk.partNumber &&
376→              i.severity === "error" &&
377→              i.type === "ValidationError"
378→          )
379→        ) {
380→          issues.push({
381→            type: "ValidationError",
382→            severity: "error",
383→            message: chunk.error,
384→            chunkPart: chunk.partNumber,
385→          });
386→        }
387→      }
388→    } else {
389→      logger.info(
390→        `[Chunk ${
391→          chunk.partNumber
392→        }] Retrying translation LLM call due to validation failure (${
393→          maxValidationRetries - attemptNum + 1
394→        } total attempts, ${
395→          maxValidationRetries - attemptNum
396→        } retries remaining)...`
397→      );
398→      // Recursive call - MAKE SURE TO PASS isLastChunk ALONG!
399→      await processTranslationChunk(
400→        chunk,
401→        config,
402→        issues,
403→        isLastChunk,
404→        failedAttemptsData,
405→        attemptNum + 1
406→      );
407→    }
408→  }
409→}
