620→// --- CLI Logic ---
621→
622→interface TranslatorCliOptions {
623→  chunkInfoPath: string;
624→  intermediateDir: string;
625→  translationModel?: string;
626→  targetLanguage?: string;
627→  promptTemplate?: string;
628→  geminiApiKey?: string;
629→  anthropicApiKey?: string;
630→  maxConcurrent?: number;
631→  retries?: number;
632→  logFile?: string;
633→  logLevel?: string;
634→  force?: boolean;
635→  processOnlyPart?: number;
636→  disableTimingValidation?: boolean;
637→}
638→
639→async function cliMain() {
640→  const program = new Command();
641→
642→  program
643→    .name("subtitle-translator")
644→    .description("Generate translations for subtitle chunks using LLMs")
645→    .requiredOption("-i, --input <path>", "Path to chunk_info.json file")
646→    .requiredOption(
647→      "-d, --intermediate-dir <path>",
648→      "Path to the intermediate directory"
649→    )
650→    .option(
651→      "-m, --model <name>",
652→      "LLM model for translation (e.g., gemini-1.5-flash-latest, claude-3-5-sonnet-20240620)"
653→    )
654→    .option(
655→      "-l, --language <lang>",
656→      "The target language (besides English)",
657→      "Korean"
658→    )
659→    .option("--prompt-template <path>", "Path to custom prompt template file")
660→    .option("--gemini-key <key>", "Gemini API Key (overrides env)")
661→    .option("--anthropic-key <key>", "Anthropic API Key (overrides env)")
662→    .option("-c, --concurrent <number>", "Max concurrent LLM calls")
663→    .option(
664→      "-r, --retries <number>",
665→      "Max retries for API errors AND validation failures",
666→      "2"
667→    )
668→    .option("--log-file <path>", "Path to log file")
669→    .option("--log-level <level>", "Log level", "info")
670→    .option(
671→      "-f, --force",
672→      "Force reprocessing even if parsed data files exist",
673→      false
674→    )
675→    .option(
676→      "--no-timing-check",
677→      "Disable subtitle timing validation checks",
678→      false
679→    )
680→    .option("-P, --part <number>", "Process only a specific part number")
681→    .parse(process.argv);
682→
683→  const opts = program.opts();
684→
685→  logger.configureLogger({
686→    logToFile: !!opts.logFile,
687→    logFilePath: opts.logFile,
688→    consoleLogLevel: opts.logLevel || "info",
689→    // fileLogLevel defaults to debug if logToFile is true
690→  });
691→
692→  const cliOptions: TranslatorCliOptions = {
693→    chunkInfoPath: opts.input,
694→    intermediateDir: opts.intermediateDir,
695→    translationModel: opts.model,
696→    targetLanguage: opts.language,
697→    promptTemplate: opts.promptTemplate,
698→    geminiApiKey: opts.geminiKey,
699→    anthropicApiKey: opts.anthropicKey,
700→    maxConcurrent: opts.concurrent ? parseInt(opts.concurrent) : undefined,
701→    retries: opts.retries ? parseInt(opts.retries) : undefined,
702→    force: opts.force || false,
703→    processOnlyPart: opts.part ? parseInt(opts.part) : undefined,
704→    disableTimingValidation: opts.noTimingCheck || false,
705→  };
706→
707→  try {
708→    logger.info(chalk.blueBright("--- Starting Translation Step ---"));
709→    const chunks = await readJsonFromFile<ChunkInfo[]>(
710→      cliOptions.chunkInfoPath
711→    );
712→    if (!chunks) {
713→      logger.error(
714→        `Failed to load chunk info from ${cliOptions.chunkInfoPath}`
715→      );
716→      process.exit(1);
717→    }
718→
719→    // Build partial config from CLI options
720→    const config: Partial<Config> = {
721→      intermediateDir: cliOptions.intermediateDir,
722→      translationModel:
723→        cliOptions.translationModel || "claude-3-5-sonnet-20240620", // Sensible default?
724→      targetLanguages: cliOptions.targetLanguage
725→        ? [cliOptions.targetLanguage.trim()]
726→        : ["Korean"],
727→      translationPromptTemplatePath: cliOptions.promptTemplate,
728→      maxConcurrent:
729→        cliOptions.maxConcurrent !== undefined ? cliOptions.maxConcurrent : 5,
730→      retries: cliOptions.retries !== undefined ? cliOptions.retries : 2,
731→      force: cliOptions.force,
732→      disableTimingValidation: cliOptions.disableTimingValidation,
733→      apiKeys: {
734→        gemini: cliOptions.geminiApiKey || process.env.GEMINI_API_KEY,
735→        anthropic: cliOptions.anthropicApiKey || process.env.ANTHROPIC_API_KEY,
736→      },
737→      processOnlyPart: cliOptions.processOnlyPart,
738→    };
739→
740→    // Validate necessary API keys based on model
741→    if (
742→      config.translationModel?.toLowerCase().includes("claude") &&
743→      !config.apiKeys?.anthropic
744→    ) {
745→      logger.error("Anthropic API key is required for Claude models.");
746→      process.exit(1);
747→    }
748→    if (
749→      !config.translationModel?.toLowerCase().includes("claude") &&
750→      !config.apiKeys?.gemini
751→    ) {
752→      logger.error("Gemini API key is required for non-Claude models.");
753→      process.exit(1);
754→    }
755→
756→    // Run translation
757→    const { chunks: updatedChunksFromRun, issues: runIssues } = await translate(
758→      chunks,
759→      config as Config
760→    );
761→
762→    // --- Filter results for reporting based on what was *intended* to run ---
763→    const targetedChunks =
764→      config.processOnlyPart !== undefined
765→        ? updatedChunksFromRun.filter(
766→            (c) => c.partNumber === config.processOnlyPart
767→          )
768→        : updatedChunksFromRun;
769→
770→    const targetedChunkNumbers = targetedChunks.map((c) => c.partNumber);
771→
772→    // Filter issues relevant to the processed chunks
773→    const relevantIssues = runIssues.filter(
774→      (i) =>
775→        i.chunkPart === undefined || targetedChunkNumbers.includes(i.chunkPart)
776→    );
777→
778→    // --- Final Reporting (Based on targeted chunks) ---
779→    logger.info(chalk.blueBright("--- Translation Step Report ---"));
780→    const successCount = targetedChunks.filter(
781→      (c) => c.status === "completed"
782→    ).length;
783→    const failCount = targetedChunks.filter(
784→      (c) => c.status === "failed"
785→    ).length;
786→    const totalProcessed = targetedChunks.length; // Count only those filtered by --part if applicable
787→
788→    let reportContent = "";
789→    reportContent += `${chalk.green(
790→      "Successful Chunks:"
791→    )} ${successCount} / ${totalProcessed}
792→`;
793→    reportContent += `${chalk.red(
794→      "Failed Chunks:"
795→    )}     ${failCount} / ${totalProcessed}
796→`;
797→    reportContent += `\n${chalk.yellowBright(
798→      "Issues Encountered During This Run:"
799→    )} (${relevantIssues})\n`;
800→
801→    if (relevantIssues.length > 0) {
802→      reportContent += `\n${chalk.yellowBright(
803→        "Issues Encountered During This Run:"
804→      )} (${relevantIssues.length})\n`;
805→      relevantIssues.forEach((issue) => {
806→        const prefix =
807→          issue.severity === "error"
808→            ? chalk.red("ERROR")
809→            : chalk.yellow("WARN");
810→        reportContent += `- ${prefix}: [Chunk ${issue.chunkPart || "N/A"}] ${
811→          issue.message
812→        }\n`;
813→      });
814→    }
815→    console.log(
816→      boxen(reportContent, {
817→        title: "Translation Step Summary",
818→        padding: 1,
819→        margin: 1,
820→        borderStyle: "round",
821→        borderColor: "magenta",
822→      })
823→    );
824→
825→    // Save the *full* updated chunk info array (includes state of non-processed chunks)
826→    const saveSuccess = await writeToFile(
827→      cliOptions.chunkInfoPath,
828→      updatedChunksFromRun
829→    );
830→    if (saveSuccess) {
831→      logger.success(
832→        `Updated chunk info saved to: ${cliOptions.chunkInfoPath}`
833→      );
834→    } else {
835→      logger.error(
836→        `Failed to save updated chunk info to: ${cliOptions.chunkInfoPath}`
837→      );
838→    }
839→
840→    // Determine exit code based on the success/failure of *targeted* chunks
841→    const targetedFailed = targetedChunks.some((c) => c.status === "failed");
842→    process.exit(targetedFailed ? 1 : 0);
843→  } catch (err: any) {
844→    logger.error(`Fatal translator error: ${err.message || err}`, err.stack);
845→    console.error(
846→      boxen(chalk.red(`Fatal Error: ${err.message || err}`), {
847→        padding: 1,
848→        margin: 1,
849→        borderColor: "red",
850→      })
851→    );
852→    process.exit(1);
853→  }
854→}
855→
856→// Run main if called directly (only when running this file standalone with Bun)
857→if (typeof Bun !== 'undefined' && import.meta.url.replace("file://", "") === Bun.main) {
858→  cliMain();
859→}
